const buildInstructionLookupNames = (fileName) => {
  if (!fileName) return [];
  const safeDecode = (() => {
    try {
      return decodeURIComponent(fileName);
    } catch (_) {
      return fileName;
    }
  })();
  const baseName = fileName
    .replace(/(_thumb)?\.(jpe?g|png|webp)$/i, "")
    .trim();
  const variants = [
    fileName,
    fileName.toLowerCase(),
    safeDecode,
    safeDecode.toLowerCase(),
    baseName,
    baseName.toLowerCase(),
    baseName.replace(/[_\s]+/g, "-"),
  ];
  return Array.from(
    new Set(variants.filter((value) => typeof value === "string" && value)),
  );
};

app.get("/assets/instructions/:fileName", async (req, res, next) => {
  const { fileName } = req.params;
  if (!fileName) return next();

  try {
    const directInstructionAsset = await maybeResolveAssetObject(
      "instruction_assets",
      "",
      fileName,
    );
    if (directInstructionAsset) {
      const directIsThumb =
        fileName === directInstructionAsset.metadata?.thumbFileName ||
        fileName === directInstructionAsset.metadata?.thumbName ||
        fileName.endsWith("_thumb.jpg") ||
        fileName.endsWith("_thumb.jpeg");
      const directInstructionVariant = {
        bucketKey: directIsThumb
          ? directInstructionAsset.metadata?.thumbBucketKey ||
            directInstructionAsset.bucketKey
          : directInstructionAsset.bucketKey,
        mimeType: directIsThumb
          ? directInstructionAsset.metadata?.thumbMime ||
            directInstructionAsset.mimeType
          : directInstructionAsset.mimeType,
      };
      if (
        directInstructionVariant.bucketKey &&
        await maybeServeBucketAsset(
          res,
          directInstructionVariant,
          directInstructionAsset.mimeType || "image/jpeg",
        )
      ) {
        return;
      }
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("instruction_assets");
    const queryOr = [{ fileName }, { thumbFileName: fileName }];
    const lookupNames = buildInstructionLookupNames(fileName);
    for (const name of lookupNames) {
      queryOr.push({ label: name });
      queryOr.push({ slug: name });
    }
    const doc = await coll.findOne({ $or: queryOr });

    if (!doc) return next();

    const isThumbRequest =
      fileName === doc.thumbFileName ||
      fileName.endsWith("_thumb.jpg") ||
      fileName.endsWith("_thumb.jpeg");

    const instructionAssetObject = await maybeResolveAssetObject(
      "instruction_assets",
      serializeDocumentId(doc._id),
      isThumbRequest ? doc.thumbFileName || fileName : doc.fileName || fileName,
    );
    const instructionBucketVariant = instructionAssetObject
      ? {
        bucketKey: isThumbRequest
          ? instructionAssetObject.metadata?.thumbBucketKey ||
            doc.thumbBucketKey ||
            instructionAssetObject.bucketKey
          : doc.bucketKey || instructionAssetObject.bucketKey,
        mimeType: isThumbRequest
          ? instructionAssetObject.metadata?.thumbMime ||
            doc.thumbMime ||
            doc.mime ||
            instructionAssetObject.mimeType
          : doc.mime || instructionAssetObject.mimeType,
      }
      : null;
    if (
      instructionBucketVariant?.bucketKey &&
      await maybeServeBucketAsset(
        res,
        instructionBucketVariant,
        doc.mime || "image/jpeg",
      )
    ) {
      return;
    }

    const { stream, mime, missingReferences } = await resolveInstructionAssetStream(
      db,
      doc,
      { isThumbRequest },
    );

    const variantMissingCompletely = (variant) => {
      const refs = missingReferences?.[variant] || {};
      const hasId = variant === "main" ? Boolean(doc.fileId) : Boolean(doc.thumbFileId);
      const hasFileName =
        variant === "main" ? Boolean(doc.fileName) : Boolean(doc.thumbFileName);
      const hasUrl = variant === "main" ? Boolean(doc.url) : Boolean(doc.thumbUrl);
      const idGone = !hasId || refs.id === true;
      const fileGone = !hasFileName || refs.filename === true;
      const urlGone = !hasUrl;
      return idGone && fileGone && urlGone;
    };

    if (!stream) {
      const mainMissing = variantMissingCompletely("main");
      const thumbMissing = variantMissingCompletely("thumb");

      if (mainMissing && thumbMissing) {
        await performInstructionAssetDeletion(db, doc);
      } else if (
        missingReferences?.main?.id ||
        missingReferences?.main?.filename ||
        missingReferences?.thumb?.id ||
        missingReferences?.thumb?.filename
      ) {
        await markInstructionAssetMissingVariants(db, doc, missingReferences);
      }
      return res.sendStatus(404);
    }

    if (
      missingReferences?.main?.id ||
      missingReferences?.main?.filename ||
      missingReferences?.thumb?.id ||
      missingReferences?.thumb?.filename
    ) {
      await markInstructionAssetMissingVariants(db, doc, missingReferences);
    }

    res.set("Content-Type", mime || doc.mime || "image/jpeg");
    res.set("Cache-Control", "public, max-age=604800, immutable");
    stream.on("error", (err) => {
      console.error(
        `[Asset Error] Failed to stream instruction asset: ${fileName}`,
        {
          error: err.message,
          code: err.code,
          fileName,
        },
      );
      if (err.code === "FileNotFound") {
        markInstructionAssetMissingVariants(db, doc, {
          main: { id: !isThumbRequest, filename: !isThumbRequest },
          thumb: { id: isThumbRequest, filename: isThumbRequest },
        }).catch(() => { });
        res.status(404).end();
        return;
      }
      next(err);
    });
    stream.pipe(res);
  } catch (err) {
    console.error(
      `[Asset Error] Error in instruction asset route: ${fileName}`,
      {
        error: err.message,
        stack: err.stack,
        fileName,
      },
    );
    next(err);
  }
});

app.get("/assets/followup/:fileName", async (req, res, next) => {
  try {
    const { fileName } = req.params;
    if (!fileName) return next();

    const directFollowUpAsset = await maybeResolveAssetObject(
      "follow_up_assets",
      "",
      fileName,
    );
    if (directFollowUpAsset) {
      const directIsThumb =
        fileName === directFollowUpAsset.metadata?.thumbFileName ||
        fileName === directFollowUpAsset.metadata?.thumbName ||
        fileName.endsWith("_thumb.jpg") ||
        fileName.endsWith("_thumb.jpeg");
      const directFollowUpVariant = {
        bucketKey: directIsThumb
          ? directFollowUpAsset.metadata?.thumbBucketKey ||
            directFollowUpAsset.bucketKey
          : directFollowUpAsset.bucketKey,
        mimeType: directIsThumb
          ? directFollowUpAsset.metadata?.thumbMime ||
            directFollowUpAsset.mimeType
          : directFollowUpAsset.mimeType,
      };
      if (
        directFollowUpVariant.bucketKey &&
        await maybeServeBucketAsset(
          res,
          directFollowUpVariant,
          directFollowUpAsset.mimeType || "image/jpeg",
        )
      ) {
        return;
      }
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("follow_up_assets");
    const doc = await coll.findOne({
      $or: [{ fileName }, { thumbName: fileName }, { thumbFileName: fileName }],
    });

    if (!doc) return next();

    const bucket = createAssetBucket(db, { bucketName: "followupAssets" });
    const isThumb =
      fileName === doc.thumbName ||
      fileName === doc.thumbFileName ||
      fileName.endsWith("_thumb.jpg") ||
      fileName.endsWith("_thumb.jpeg");
    const followUpAssetObject = await maybeResolveAssetObject(
      "follow_up_assets",
      serializeDocumentId(doc._id),
      isThumb
        ? doc.thumbFileName || doc.thumbName || fileName
        : doc.fileName || fileName,
    );
    const followUpBucketVariant = followUpAssetObject
      ? {
        bucketKey: isThumb
          ? followUpAssetObject.metadata?.thumbBucketKey ||
            doc.thumbBucketKey ||
            followUpAssetObject.bucketKey
          : doc.bucketKey || followUpAssetObject.bucketKey,
        mimeType: isThumb
          ? followUpAssetObject.metadata?.thumbMime ||
            doc.thumbMime ||
            doc.mime ||
            followUpAssetObject.mimeType
          : doc.mime || followUpAssetObject.mimeType,
      }
      : null;
    if (
      followUpBucketVariant?.bucketKey &&
      await maybeServeBucketAsset(
        res,
        followUpBucketVariant,
        doc.mime || "image/jpeg",
      )
    ) {
      return;
    }

    const targetName = isThumb
      ? doc.thumbFileName || doc.thumbName
      : doc.fileName;
    const targetId = isThumb ? doc.thumbFileId || null : doc.fileId || null;
    if (!targetName) return next();
    let fileObjectId = toObjectId(targetId);

    if (!fileObjectId) {
      const files = await bucket
        .find({ filename: targetName })
        .sort({ uploadDate: -1 })
        .limit(1)
        .toArray();
      if (!files.length) return next();
      fileObjectId = files[0]._id;
    }

    const stream = bucket.openDownloadStream(fileObjectId);

    res.set("Content-Type", doc.mime || "image/jpeg");
    res.set("Cache-Control", "public, max-age=604800, immutable");
    stream.on("error", (err) => {
      console.error(`[Asset Error] Failed to stream followup asset: ${fileName}`, {
        error: err.message,
        code: err.code,
        fileName,
        targetName,
        targetId,
        fileObjectId,
      });
      if (err.code === "FileNotFound") return next();
      next(err);
    });
    stream.pipe(res);
  } catch (err) {
    console.error(`[Asset Error] Error in followup asset route: ${fileName}`, {
      error: err.message,
      stack: err.stack,
      fileName,
    });
    next(err);
  }
});

app.get("/assets/chat-images/:messageId/:imageIndex", async (req, res) => {
  try {
    const { messageId, imageIndex } = req.params;
    const index = Number.parseInt(imageIndex, 10);
    if (!Number.isFinite(index) || index < 0) {
      return res.sendStatus(404);
    }

    if (chatStorageService.isConfigured()) {
      const attachment = await chatStorageService.getAttachment(messageId, index);
      if (attachment) {
        if (attachment.bucket_key && projectBucket.isConfigured()) {
          const objectPayload = await projectBucket.getObjectBuffer(
            attachment.bucket_key,
          );
          if (objectPayload.buffer?.length) {
            res.set(
              "Content-Type",
              objectPayload.contentType ||
                attachment.content_type ||
                "image/jpeg",
            );
            res.set("Cache-Control", "no-store");
            return res.end(objectPayload.buffer);
          }
        }

        if (
          attachment.source_url &&
          /^https?:\/\//i.test(attachment.source_url)
        ) {
          return res.redirect(attachment.source_url);
        }
      }
    }

    if (!ObjectId.isValid(messageId)) {
      return res.sendStatus(404);
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const doc = await db.collection("chat_history").findOne(
      { _id: new ObjectId(messageId) },
      { projection: { content: 1 } },
    );

    if (!doc) {
      return res.sendStatus(404);
    }

    const images = extractBase64ImagesFromContent(doc.content);
    const payload = images[index];
    if (!payload || !payload.base64) {
      return res.sendStatus(404);
    }

    const buffer = Buffer.from(payload.base64, "base64");
    if (!buffer.length) {
      return res.sendStatus(404);
    }

    const contentType = payload.mime || detectImageMimeType(payload.base64);
    res.set("Content-Type", contentType || "image/jpeg");
    res.set("Cache-Control", "no-store");
    return res.end(buffer);
  } catch (err) {
    console.error("[Chat Images] ไม่สามารถดึงรูปภาพแชทได้:", err?.message || err);
    return res.sendStatus(500);
  }
});

