const CHAT_ADMIN_AUX_CACHE_TTL_MS = Math.max(
  1000,
  Number.parseInt(process.env.CHAT_ADMIN_AUX_CACHE_TTL_MS || "5000", 10) || 5000,
);
const CHAT_ADMIN_AUX_CACHE_STALE_MS = Math.max(
  CHAT_ADMIN_AUX_CACHE_TTL_MS,
  Number.parseInt(process.env.CHAT_ADMIN_AUX_CACHE_STALE_MS || "300000", 10) || 300000,
);
const chatAdminAuxCache = new Map();

function invalidateChatUsersAuxCache() {
  if (!chatAdminAuxCache || chatAdminAuxCache.size === 0) return;
  chatAdminAuxCache.delete("chat:users");
  clearCacheMapEntriesByPrefix(chatAdminAuxCache, "chat:users:focus:");
}

function getChatAdminAuxCacheEntry(key) {
  return chatAdminAuxCache.get(key) || {
    value: null,
    expiresAt: 0,
    staleUntil: 0,
    refreshPromise: null,
  };
}

function setChatAdminAuxCacheEntry(key, value) {
  const now = Date.now();
  chatAdminAuxCache.set(key, {
    value,
    expiresAt: now + CHAT_ADMIN_AUX_CACHE_TTL_MS,
    staleUntil: now + CHAT_ADMIN_AUX_CACHE_STALE_MS,
    refreshPromise: null,
  });
  return value;
}

async function getCachedChatAdminAuxValue(key, loader, fallbackValue) {
  const now = Date.now();
  const entry = getChatAdminAuxCacheEntry(key);
  if (entry.value !== null && entry.expiresAt > now) {
    return entry.value;
  }

  const refresh = async () => {
    try {
      const value = await loader();
      return setChatAdminAuxCacheEntry(key, value);
    } catch (error) {
      console.error(`[ChatAdminCache] refresh failed for ${key}:`, error?.message || error);
      return entry.value !== null ? entry.value : fallbackValue;
    }
  };

  if (entry.value !== null && entry.staleUntil > now) {
    if (!entry.refreshPromise) {
      entry.refreshPromise = refresh().finally(() => {
        const latest = getChatAdminAuxCacheEntry(key);
        if (latest.refreshPromise === entry.refreshPromise) {
          latest.refreshPromise = null;
          chatAdminAuxCache.set(key, latest);
        }
      });
      chatAdminAuxCache.set(key, entry);
    }
    return entry.value;
  }

  if (!entry.refreshPromise) {
    entry.refreshPromise = refresh().finally(() => {
      const latest = getChatAdminAuxCacheEntry(key);
      if (latest.refreshPromise === entry.refreshPromise) {
        latest.refreshPromise = null;
        chatAdminAuxCache.set(key, latest);
      }
    });
    chatAdminAuxCache.set(key, entry);
  }
  return entry.refreshPromise;
}

function maybeLogAppDocumentShadowMismatch(scope, sourcePayload, postgresPayload) {
  try {
    const sourceSerialized = JSON.stringify(normalizeValueForStorageMirror(sourcePayload));
    const postgresSerialized = JSON.stringify(
      normalizeValueForStorageMirror(postgresPayload),
    );
    if (sourceSerialized !== postgresSerialized) {
      logShadowReadMismatch(`app_document:${scope}`, {
        source: sourcePayload,
        postgres: postgresPayload,
      });
    }
  } catch (_) {
    // Shadow comparison must never affect the request path.
  }
}

async function maybeUploadBufferToProjectBucket(
  scope,
  assetId,
  fileName,
  buffer,
  options = {},
) {
  if (!projectBucket.isConfigured()) {
    return null;
  }

  const normalizedScope =
    typeof scope === "string" && scope.trim() ? scope.trim() : "assets";
  const normalizedAssetId =
    typeof assetId === "string" && assetId.trim()
      ? assetId.trim()
      : crypto.randomBytes(12).toString("hex");
  const normalizedFileName =
    typeof fileName === "string" && fileName.trim() ? fileName.trim() : "file";
  const objectKey = projectBucket.buildKey(
    "assets",
    normalizedScope,
    normalizedAssetId,
    normalizedFileName,
  );

  await projectBucket.putBuffer(objectKey, buffer, {
    contentType: options.contentType,
    cacheControl:
      options.cacheControl || "private, max-age=31536000, immutable",
    metadata: options.metadata,
  });

  return objectKey;
}

async function maybeDeleteBucketObjectKeys(keys = []) {
  if (!projectBucket.isConfigured() || !Array.isArray(keys) || !keys.length) {
    return;
  }

  for (const key of keys) {
    if (typeof key !== "string" || !key.trim()) continue;
    try {
      await projectBucket.deleteObject(key.trim());
    } catch (error) {
      console.warn(
        "[Bucket] delete object failed:",
        error?.message || error,
      );
    }
  }
}

async function maybeResolveAssetObject(scope, assetId, fallbackFileName = "") {
  if (!chatStorageService.isConfigured()) {
    return null;
  }

  try {
    if (typeof assetId === "string" && assetId.trim()) {
      const byId = await chatStorageService.getAssetObject(scope, assetId.trim());
      if (byId) return byId;
    }
    if (typeof fallbackFileName === "string" && fallbackFileName.trim()) {
      return await chatStorageService.findAssetObjectByFileName(
        scope,
        fallbackFileName.trim(),
      );
    }
  } catch (error) {
    console.warn(
      `[Bucket] resolve asset object failed for ${scope}:`,
      error?.message || error,
    );
  }
  return null;
}

async function maybeServeBucketAsset(res, assetObject = null, fallbackMime = "") {
  if (
    !assetObject ||
    !assetObject.bucketKey ||
    !projectBucket.isConfigured()
  ) {
    return false;
  }

  try {
    const payload = await projectBucket.getObjectBuffer(assetObject.bucketKey);
    if (!payload.buffer?.length) {
      return false;
    }

    res.set(
      "Content-Type",
      payload.contentType || assetObject.mimeType || fallbackMime || "application/octet-stream",
    );
    res.set("Cache-Control", "public, max-age=604800, immutable");
    res.end(payload.buffer);
    return true;
  } catch (error) {
    console.warn(
      "[Bucket] serve asset fallback to local asset storage:",
      error?.message || error,
    );
    return false;
  }
}

