// API: Create new instruction
app.post("/api/instructions-v2", async (req, res) => {
  try {
    const { name, description } = req.body;

    if (!name || name.trim() === "") {
      return res.status(400).json({ success: false, error: "กรุณาระบุชื่อ Instruction" });
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("instructions_v2");

    const now = new Date();
    const starterDataItems = buildRetailTemplateDataItems({
      pageName: name.trim(),
    });
    const instruction = {
      instructionId: generateInstructionId(),
      name: name.trim(),
      description: (description || "").trim(),
      templateType: "retail_sales",
      dataItems: starterDataItems,
      dataItemRoles: {
        role: starterDataItems[0]?.itemId || null,
        catalog: starterDataItems[1]?.itemId ? [starterDataItems[1].itemId] : [],
        scenarios: starterDataItems[2]?.itemId ? [starterDataItems[2].itemId] : [],
      },
      retailProfile: {
        defaultPaymentMode: "cod",
        primaryLanguage: "th",
        orderRequiredFields: ["items", "quantity", "name", "address", "phone"],
        cutPolicy: { enabled: true, maxLinesBeforeCut: 3 },
        imagePolicy: { sendProductImageOnInterest: true, maxImagesPerAnswer: 1 },
      },
      conversationStarter: {
        enabled: false,
        messages: [],
        updatedAt: now,
      },
      usageCount: 0,
      createdAt: now,
      updatedAt: now
    };

    const result = await coll.insertOne(instruction);
    const createdId = result.insertedId;
    instruction._id = createdId.toString();
    const snapshotResult = await createDashboardSnapshotOrThrow(
      createdId,
      "create_instruction",
      db,
      "dashboard_api",
    );
    instruction.version = snapshotResult.version;
    instruction.updatedAt = snapshotResult.snapshotAt;
    await maybeMirrorInstructionV2Document(db, createdId);
    invalidateInstructionsV2Cache();

    res.json({ success: true, instruction });
  } catch (err) {
    console.error("Error creating instruction v2:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

// API: Update instruction (name, description only)
app.put("/api/instructions-v2/:id", async (req, res) => {
  try {
    const { id } = req.params;
    const { name, description, conversationStarter } = req.body || {};

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("instructions_v2");

    const updateData = { updatedAt: new Date() };
    if (name !== undefined) updateData.name = name.trim();
    if (description !== undefined) updateData.description = description.trim();
    if (conversationStarter !== undefined) {
      const normalizedStarter = normalizeConversationStarterConfig(
        conversationStarter,
      );
      updateData.conversationStarter = {
        enabled: !!normalizedStarter.enabled,
        messages: normalizedStarter.messages,
        updatedAt: new Date(),
      };
    }

    const result = await coll.updateOne(
      { _id: toObjectId(id) },
      { $set: updateData }
    );

    if (result.matchedCount === 0) {
      return res.status(404).json({ success: false, error: "ไม่พบ Instruction" });
    }
    await createDashboardSnapshotOrThrow(
      id,
      "update_instruction",
      db,
      "dashboard_api",
    );

    const instruction = await coll.findOne({ _id: toObjectId(id) });
    await maybeMirrorInstructionV2Document(db, instruction);
    invalidateInstructionsV2Cache();
    res.json({
      success: true,
      instruction: normalizeInstructionV2Document(instruction, id),
    });
  } catch (err) {
    console.error("Error updating instruction v2:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

