async function ensureSettings() {
  // ตรวจสอบและสร้างการตั้งค่าเริ่มต้น
  const defaultSettings = [
    { key: "aiEnabled", value: true },
    { key: "chatDelaySeconds", value: 0 },
    { key: "maxQueueMessages", value: 10 },
    { key: "enableMessageMerging", value: true },
    { key: "textModel", value: DEFAULT_ASSISTANT_MODEL },
    { key: "visionModel", value: DEFAULT_ASSISTANT_MODEL },
    { key: "maxImagesPerMessage", value: 3 },
    { key: "maxHistoryImagesForAI", value: 2 },
    { key: "defaultInstruction", value: "" },
    { key: "enableChatHistory", value: true },
    { key: "enableAdminNotifications", value: true },
    { key: "systemMode", value: "production" },
    { key: "showTokenUsage", value: false },
    { key: "facebookImageSendMode", value: "upload" },
    { key: "followUpAutoEnabled", value: false },
    { key: "orderCutoffSchedulingEnabled", value: true },
    {
      key: "orderRequiredFields",
      value: { ...ORDER_REQUIRED_FIELDS_DEFAULT },
    },
    {
      key: "audioAttachmentResponse",
      value: DEFAULT_AUDIO_ATTACHMENT_RESPONSE,
    },
    { key: "enableAudioTranscription", value: true },
    { key: "audioTranscriptionModel", value: DEFAULT_AUDIO_TRANSCRIPTION_MODEL },
    {
      key: "followUpRounds",
      value: [
        { delayMinutes: 10, message: "ยังสนใจไหม" },
        { delayMinutes: 20, message: "เหลืออีกเพียงสิบท่าน" },
      ],
    },
  ];

  const readAppDocumentsFromPostgres = isPostgresAppDocumentReadEnabled();
  let coll = null;
  if (!readAppDocumentsFromPostgres) {
    const client = await connectDB();
    const db = client.db("chatbot");
    coll = db.collection("settings");
  }

  for (const setting of defaultSettings) {
    if (readAppDocumentsFromPostgres) {
      const existing = await maybeReadAppDocumentPayload("settings", setting.key);
      if (!existing) {
        await maybeMirrorAppDocument(
          "settings",
          setting.key,
          normalizeValueForStorageMirror(setting),
        );
        console.log(
          `[SETTINGS] สร้างการตั้งค่าเริ่มต้น: ${setting.key} = ${setting.value}`,
        );
      }
      continue;
    }

    const existing = await coll.findOne({ key: setting.key });
    if (!existing) {
      await coll.insertOne(setting);
      await maybeMirrorAppDocument(
        "settings",
        setting.key,
        normalizeValueForStorageMirror(setting),
      );
      console.log(
        `[SETTINGS] สร้างการตั้งค่าเริ่มต้น: ${setting.key} = ${setting.value}`,
      );
    }
  }
}

function parseOptionalBoolean(value) {
  if (typeof value === "boolean") return value;
  if (typeof value === "string") {
    const normalized = value.trim().toLowerCase();
    if (normalized === "true") return true;
    if (normalized === "false") return false;
  }
  return undefined;
}

// Get setting value with default fallback
const _settingsCache = new Map(); // key → { value, expireAt }
const _SETTINGS_CACHE_TTL_MS = 30_000; // 30 วินาที

async function getSettingValue(key, defaultValue) {
  try {
    const cached = _settingsCache.get(key);
    if (cached && Date.now() < cached.expireAt) {
      return cached.value;
    }

    if (isPostgresAppDocumentReadEnabled()) {
      const pgDoc = await maybeReadAppDocumentPayload("settings", key);
      const value =
        !pgDoc || typeof pgDoc.value === "undefined" ? defaultValue : pgDoc.value;
      _settingsCache.set(key, { value, expireAt: Date.now() + _SETTINGS_CACHE_TTL_MS });
      return value;
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("settings");
    const doc = await coll.findOne({ key });
    const value = !doc || typeof doc.value === "undefined" ? defaultValue : doc.value;
    if (isShadowAppDocumentReadEnabled()) {
      const pgDoc = await maybeReadAppDocumentPayload("settings", key);
      const pgValue =
        !pgDoc || typeof pgDoc.value === "undefined" ? defaultValue : pgDoc.value;
      maybeLogAppDocumentShadowMismatch(`settings/${key}`, value, pgValue);
    }
    _settingsCache.set(key, { value, expireAt: Date.now() + _SETTINGS_CACHE_TTL_MS });
    return value;
  } catch (error) {
    console.error(`Error getting setting ${key}:`, error);
    return defaultValue;
  }
}

async function setSettingValue(key, value) {
  try {
    if (isPostgresAppDocumentReadEnabled()) {
      await maybeMirrorAppDocument("settings", key, { key, value });
      _settingsCache.delete(key);
      return true;
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("settings");
    await coll.updateOne({ key }, { $set: { value } }, { upsert: true });
    await maybeMirrorAppDocument("settings", key, { key, value });
    _settingsCache.delete(key); // invalidate cache ทันที
    return true;
  } catch (error) {
    console.error(`Error setting ${key}:`, error);
    return false;
  }
}

function invalidateSettingsCacheKeys(keys = []) {
  if (!Array.isArray(keys)) return;
  for (const key of keys) {
    if (typeof key === "string" && key.trim()) {
      _settingsCache.delete(key.trim());
    }
  }
}

