// Create new Line Bot
app.post("/api/line-bots", async (req, res) => {
  try {
    const {
      name,
      description,
      channelAccessToken,
      channelSecret,
      webhookUrl,
      status,
      isDefault,
      aiModel,
      selectedInstructions,
      selectedImageCollections,
      openaiApiKeyId,
    } = req.body;
    const notificationEnabled = parseOptionalBoolean(
      req.body?.notificationEnabled,
    );

    if (!name || !channelAccessToken || !channelSecret) {
      return res
        .status(400)
        .json({ error: "กรุณากรอกข้อมูลที่จำเป็นให้ครบถ้วน" });
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("line_bots");

    // If this is default, unset other defaults
    if (isDefault) {
      await coll.updateMany({}, { $set: { isDefault: false } });
    }

    // Generate unique webhook URL if not provided
    let finalWebhookUrl = webhookUrl;
    if (!finalWebhookUrl) {
      const baseUrl =
        process.env.PUBLIC_BASE_URL || "https://" + req.get("host");
      const uniqueId =
        Date.now().toString(36) + Math.random().toString(36).substr(2);
      finalWebhookUrl = `${baseUrl}/webhook/line/${uniqueId}`;
    }

    const normalizedSelections = normalizeLatestOnlyInstructionSelections(
      selectedInstructions || [],
    );
    const normalizedCollections = normalizeImageCollectionSelections(
      selectedImageCollections || [],
    );
    const resolvedAiModel = aiModel || DEFAULT_ASSISTANT_MODEL;
    const resolvedAiConfigRaw = req.body.aiConfig || req.body;
    const reasoningError = getBotReasoningValidationError(
      resolvedAiModel,
      resolvedAiConfigRaw,
    );
    if (reasoningError) {
      return res.status(400).json({ error: reasoningError });
    }

    const lineBot = {
      name,
      description: description || "",
      channelAccessToken,
      channelSecret,
      webhookUrl: finalWebhookUrl,
      status: status || "active",
      isDefault: isDefault || false,
      notificationEnabled: notificationEnabled !== false,
      aiModel: resolvedAiModel, // AI Model เฉพาะสำหรับ Line Bot นี้
      aiConfig: normalizeAiConfig(resolvedAiConfigRaw),
      selectedInstructions: normalizedSelections,
      selectedImageCollections: normalizedCollections,
      openaiApiKeyId: openaiApiKeyId || null,
      keywordSettings: {
        enableAI: { keyword: "", response: "", sendResponse: false },
        disableAI: { keyword: "", response: "", sendResponse: false },
        disableFollowUp: { keyword: "", response: "", sendResponse: false },
      },
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    const result = await coll.insertOne(lineBot);
    lineBot._id = result.insertedId;
    if (isDefault) {
      await maybeMirrorAppDocumentSelection(db, "line_bots", null, {
        mirrorAll: true,
      });
    } else {
      await maybeMirrorAppDocumentFromCollection("line_bots", lineBot);
    }

    res.status(201).json(lineBot);
  } catch (err) {
    console.error("Error creating line bot:", err);
    res.status(500).json({ error: "ไม่สามารถสร้าง Line Bot ได้" });
  }
});

// Update Line Bot
app.put("/api/line-bots/:id", async (req, res) => {
  try {
    const { id } = req.params;
    const {
      name,
      description,
      channelAccessToken,
      channelSecret,
      webhookUrl,
      status,
      isDefault,
      selectedImageCollections,
    } = req.body;
    const notificationEnabled = parseOptionalBoolean(
      req.body?.notificationEnabled,
    );

    if (!name || !channelAccessToken || !channelSecret) {
      return res
        .status(400)
        .json({ error: "กรุณากรอกข้อมูลที่จำเป็นให้ครบถ้วน" });
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("line_bots");

    const existing = await coll.findOne({ _id: new ObjectId(id) });
    if (!existing) {
      return res.status(404).json({ error: "ไม่พบ Line Bot ที่ระบุ" });
    }

    // If this is default, unset other defaults
    if (isDefault) {
      await coll.updateMany(
        { _id: { $ne: new ObjectId(id) } },
        { $set: { isDefault: false } },
      );
    }

    const resolvedAiModel =
      req.body.aiModel || existing.aiModel || DEFAULT_ASSISTANT_MODEL;
    const resolvedAiConfigRaw = req.body.aiConfig
      ? req.body.aiConfig
      : { ...existing.aiConfig, ...req.body };
    const reasoningError = getBotReasoningValidationError(
      resolvedAiModel,
      resolvedAiConfigRaw,
    );
    if (reasoningError) {
      return res.status(400).json({ error: reasoningError });
    }

    const updateData = {
      name,
      description: description || "",
      channelAccessToken,
      channelSecret,
      webhookUrl: webhookUrl || "",
      status: status || "active",
      isDefault: isDefault || false,
      aiModel: resolvedAiModel, // AI Model เฉพาะสำหรับ Line Bot นี้
      aiConfig: normalizeAiConfig(resolvedAiConfigRaw),
      openaiApiKeyId: req.body.openaiApiKeyId !== undefined ? (req.body.openaiApiKeyId || null) : existing.openaiApiKeyId,
      updatedAt: new Date(),
    };
    if (typeof notificationEnabled === "boolean") {
      updateData.notificationEnabled = notificationEnabled;
    }

    if (Array.isArray(selectedImageCollections)) {
      updateData.selectedImageCollections = normalizeImageCollectionSelections(
        selectedImageCollections,
      );
    } else if (selectedImageCollections === null) {
      updateData.selectedImageCollections = [];
    }

    const result = await coll.updateOne(
      { _id: new ObjectId(id) },
      { $set: updateData },
    );

    if (result.matchedCount === 0) {
      return res.status(404).json({ error: "ไม่พบ Line Bot ที่ระบุ" });
    }

    await maybeMirrorAppDocumentSelection(db, "line_bots", id, {
      mirrorAll: Boolean(isDefault),
    });
    lineBotCredentialCache.delete(normalizeRuntimeCacheId(id, ""));
    invalidateBotRuntimeCaches("line", id);
    res.json({ message: "อัปเดต Line Bot เรียบร้อยแล้ว" });
  } catch (err) {
    console.error("Error updating line bot:", err);
    res.status(500).json({ error: "ไม่สามารถอัปเดต Line Bot ได้" });
  }
});

