// Enhanced delete instruction with JSON response
app.delete("/admin/instructions/:id", async (req, res) => {
  try {
    const { id } = req.params;
    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("instructions");

    const deleteQueries = [];
    if (ObjectId.isValid(id)) {
      deleteQueries.push({ _id: new ObjectId(id) });
    }
    deleteQueries.push({ _id: id }); // กรณีที่ _id ถูกเก็บเป็นสตริง
    deleteQueries.push({ instructionId: id });

    let deleted = 0;
    for (const condition of deleteQueries) {
      const result = await coll.deleteOne(condition);
      if (result.deletedCount > 0) {
        deleted = result.deletedCount;
        break;
      }
    }

    if (deleted > 0) {
      invalidateInstructionPromptCaches();
      res.json({ success: true, message: "ลบข้อมูลเรียบร้อยแล้ว" });
    } else {
      res.json({ success: false, error: "ไม่พบข้อมูลที่ต้องการลบ" });
    }
  } catch (err) {
    console.error("Delete instruction error:", err);
    res.json({ success: false, error: "ไม่สามารถลบข้อมูลได้" });
  }
});

// Show JSON for a table instruction
app.get("/admin/instructions/:id/json", async (req, res) => {
  try {
    const { id } = req.params;
    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("instructions");
    const instruction = await coll.findOne({ _id: new ObjectId(id) });
    if (!instruction || instruction.type !== "table") {
      return res.json({
        success: false,
        error: "ไม่พบ instruction หรือตรงประเภท",
      });
    }
    res.json({
      success: true,
      tableData: instruction.data,
      title: instruction.title || "",
    });
  } catch (err) {
    res.json({ success: false, error: err.message });
  }
});

// ==========================================
// Broadcast System - Queue & Helpers
// ==========================================

const activeBroadcasts = new Map();

class BroadcastQueue {
  constructor(jobId, data, options = {}, channelInfo = {}) {
    this.jobId = jobId;
    this.data = data; // { messages, targets, channels }
    this.options = options; // { batchSize, batchDelay, messageDelay }
    this.isCancelled = false;
    this.botsCache = new Map();

    // Group targets by platform:botId for parallel processing
    const grouped = {};
    for (const t of data.targets) {
      const key = `${t.platform}:${t.botId}`;
      if (!grouped[key]) grouped[key] = [];
      grouped[key].push(t);
    }
    this.channelGroups = grouped;

    // Build per-channel stats
    const channels = {};
    for (const [key, targets] of Object.entries(grouped)) {
      const info = channelInfo[key] || {};
      channels[key] = {
        name: info.name || key,
        platform: info.platform || key.split(":")[0],
        total: targets.length,
        sent: 0,
        failed: 0,
        status: "pending",
      };
    }

    this.stats = {
      total: data.targets.length,
      sent: 0,
      failed: 0,
      status: "pending",
      startTime: null,
      endTime: null,
      errors: [],
      channels,
    };
  }

  // --- Parallel start: each channel runs its own batch loop concurrently ---
  async start() {
    this.stats.status = "running";
    this.stats.startTime = new Date();
    await this.saveHistory();

    try {
      await this.loadBots();

      const channelPromises = Object.entries(this.channelGroups).map(
        ([channelKey, targets]) => this.processChannel(channelKey, targets)
      );

      await Promise.allSettled(channelPromises);

      this.recomputeOverallStats();
      this.stats.status = this.isCancelled ? "cancelled" : "completed";
    } catch (error) {
      console.error(`[Broadcast] Job ${this.jobId} failed:`, error);
      this.stats.status = "failed";
      this.stats.errors.push({ error: error.message, timestamp: new Date() });
    } finally {
      this.stats.endTime = new Date();
      await this.saveHistory();
      setTimeout(() => activeBroadcasts.delete(this.jobId), 5 * 60 * 1000);
    }
  }

  // --- Process one channel's targets in batches ---
  async processChannel(channelKey, channelTargets) {
    const channelStats = this.stats.channels[channelKey];
    channelStats.status = "running";

    const { batchSize = 10, batchDelay = 60, messageDelay = 1 } = this.options;

    try {
      for (let i = 0; i < channelTargets.length; i += batchSize) {
        if (this.isCancelled) break;

        const batch = channelTargets.slice(i, i + batchSize);

        const batchPromises = batch.map(async (target, index) => {
          if (this.isCancelled) return;
          if (messageDelay > 0 && index > 0) {
            await new Promise((r) => setTimeout(r, index * messageDelay * 1000));
          }
          if (this.isCancelled) return;

          try {
            await this._deliverToTarget(target);
            channelStats.sent++;
          } catch (e) {
            console.error(`[Broadcast] Failed to send to ${target.userId}: ${e.message}`);
            channelStats.failed++;
            if (this.stats.errors.length < 100) {
              this.stats.errors.push({ userId: target.userId, error: e.message, channel: channelKey });
            }
          }
        });

        await Promise.allSettled(batchPromises);
        this.recomputeOverallStats();
        await this.updateProgress();

        if (i + batchSize < channelTargets.length && !this.isCancelled) {
          await new Promise((r) => setTimeout(r, batchDelay * 1000));
        }
      }

      channelStats.status = this.isCancelled ? "cancelled" : "completed";
    } catch (error) {
      channelStats.status = "failed";
      console.error(`[Broadcast] Channel ${channelKey} failed:`, error);
    }
  }

  // --- Pure delivery — throws on error, no stat tracking ---
  async _deliverToTarget(target) {
    const { userId, platform, botId } = target;
    const { messages } = this.data;
    const bot = this.botsCache.get(`${platform}:${botId}`);

    if (!bot) {
      throw new Error("Bot not found");
    }

    if (platform === "facebook") {
      for (const msg of messages) {
        if (msg.type === 'text') {
          await sendFacebookMessage(userId, msg.content, bot.accessToken, { metadata: "broadcast_auto" });
        } else if (msg.type === 'image') {
          await axios.post(
            `https://graph.facebook.com/v18.0/me/messages`,
            {
              recipient: { id: userId },
              message: {
                attachment: {
                  type: "image",
                  payload: { url: msg.url, is_reusable: true }
                },
                metadata: "broadcast_auto"
              }
            },
            {
              params: { access_token: bot.accessToken },
              headers: { "Content-Type": "application/json" }
            }
          );
        }
      }
    } else if (platform === "line") {
      const client = createLineClient(bot.channelAccessToken, bot.channelSecret);
      const lineMessages = messages.map(msg => {
        if (msg.type === 'text') {
          return { type: 'text', text: normalizeOutgoingText(msg.content) };
        }
        if (msg.type === 'image') return { type: 'image', originalContentUrl: msg.url, previewImageUrl: msg.url };
        return null;
      }).filter(Boolean);

      if (lineMessages.length > 0) {
        await client.pushMessage(userId, lineMessages);
      }
    } else if (platform === "instagram") {
      const accessToken = resolveMetaAccessToken(bot || {});
      const senderId = resolveInstagramSenderId(bot || {});
      if (!accessToken || !senderId) {
        throw new Error("Instagram bot access token/sender id missing");
      }
      for (const msg of messages) {
        if (msg.type === "text") {
          await sendInstagramMessage(userId, msg.content, accessToken, senderId);
        } else if (msg.type === "image" && msg.url) {
          const label = msg.alt || msg.caption || "Broadcast image";
          const assetsMap = buildAssetsLookup([
            { label, url: msg.url, thumbUrl: msg.url, alt: msg.alt || "", fileName: "" },
          ]);
          await sendInstagramMessage(
            userId, `#[IMAGE:${label}]`, accessToken, senderId,
            { selectedImageCollections: null }, assetsMap,
          );
        }
      }
    } else if (platform === "whatsapp") {
      const accessToken = resolveMetaAccessToken(bot || {});
      const phoneNumberId = resolveWhatsAppPhoneNumberId(bot || {});
      if (!accessToken || !phoneNumberId) {
        throw new Error("WhatsApp bot access token/phoneNumberId missing");
      }
      for (const msg of messages) {
        if (msg.type === "text") {
          await sendWhatsAppMessage(userId, msg.content, accessToken, phoneNumberId);
        } else if (msg.type === "image" && msg.url) {
          await sendWhatsAppImageByUrl(userId, msg.url, accessToken, phoneNumberId, msg.alt || "");
        }
      }
    }
  }

  // --- Sum per-channel stats into top-level for backward compat ---
  recomputeOverallStats() {
    let sent = 0, failed = 0;
    for (const ch of Object.values(this.stats.channels)) {
      sent += ch.sent;
      failed += ch.failed;
    }
    this.stats.sent = sent;
    this.stats.failed = failed;
  }

  cancel() {
    this.isCancelled = true;
  }

  async loadBots() {
    const client = await connectDB();
    const db = client.db("chatbot");
    const botKeys = new Set(this.data.targets.map(t => `${t.platform}:${t.botId}`));

    for (const key of botKeys) {
      const [platform, botId] = key.split(":");
      if (!botId || !ObjectId.isValid(botId)) continue;

      let bot;
      if (platform === 'facebook') {
        bot = await db.collection("facebook_bots").findOne({ _id: new ObjectId(botId) });
      } else if (platform === 'line') {
        bot = await db.collection("line_bots").findOne({ _id: new ObjectId(botId) });
      } else if (platform === "instagram") {
        bot = await db.collection("instagram_bots").findOne({ _id: new ObjectId(botId) });
      } else if (platform === "whatsapp") {
        bot = await db.collection("whatsapp_bots").findOne({ _id: new ObjectId(botId) });
      }

      if (bot) {
        this.botsCache.set(key, bot);
      }
    }
  }

  async saveHistory() {
    try {
      const client = await connectDB();
      const db = client.db("chatbot");
      const coll = db.collection("broadcast_history");
      await coll.updateOne(
        { _id: new ObjectId(this.jobId) },
        { $set: { stats: this.stats, updatedAt: new Date() } },
        { upsert: true }
      );
    } catch (e) {
      console.error("[Broadcast] Failed to save history:", e);
    }
  }

  async updateProgress() {
    if (typeof io !== 'undefined') {
      io.to("admin").emit("broadcastProgress", { jobId: this.jobId, stats: this.stats });
    }
    await this.saveHistory();
  }
}

async function getBroadcastAudience(channels, audienceType) {
  const client = await connectDB();
  const db = client.db("chatbot");
  const chatColl = db.collection("chat_history");
  const followUpColl = db.collection("follow_up_status");

  let users = [];
  const getChatUserIdsForChannel = async (platform, botId) => {
    const pipeline = [
      { $match: { platform, botId, role: "user" } },
      {
        $addFields: {
          userKey: {
            $let: {
              vars: {
                raw: {
                  $cond: [
                    {
                      $or: [
                        { $eq: ["$senderId", null] },
                        { $eq: ["$senderId", ""] },
                      ],
                    },
                    "$userId",
                    "$senderId",
                  ],
                },
              },
              in: {
                $cond: [
                  {
                    $or: [
                      { $eq: ["$$raw", null] },
                      { $eq: ["$$raw", ""] },
                    ],
                  },
                  null,
                  {
                    $convert: {
                      input: "$$raw",
                      to: "string",
                      onError: null,
                      onNull: null,
                    },
                  },
                ],
              },
            },
          },
        },
      },
      { $match: { userKey: { $nin: [null, ""] } } },
      { $group: { _id: "$userKey" } },
    ];

    const rows = await chatColl.aggregate(pipeline).toArray();
    return rows.map((row) => row._id).filter(Boolean);
  };

  for (const ch of channels) {
    const [platform, botId] = ch.split(":");

    // Base query: all users for this bot
    let userIds = await getChatUserIdsForChannel(platform, botId);

    if (audienceType === 'all') {
      // No filter
    } else if (audienceType === 'tagged') {
      // Filter only those with hasFollowUp: true
      const taggedUsers = await followUpColl.find({
        senderId: { $in: userIds },
        hasFollowUp: true
      }).project({ senderId: 1 }).toArray();
      const taggedSet = new Set(taggedUsers.map(u => u.senderId));
      userIds = userIds.filter(id => taggedSet.has(id));
    } else if (audienceType === 'untagged') {
      // Filter exclude hasFollowUp: true
      const taggedUsers = await followUpColl.find({
        senderId: { $in: userIds },
        hasFollowUp: true
      }).project({ senderId: 1 }).toArray();
      const taggedSet = new Set(taggedUsers.map(u => u.senderId));
      userIds = userIds.filter(id => !taggedSet.has(id));
    }

    // Map to target objects
    users.push(...userIds.map(id => ({ userId: id, platform, botId })));
  }

  // Deduplicate: same userId+platform can appear if selected multiple bots
  const seen = new Set();
  return users.filter(u => {
    const key = `${u.platform}:${u.userId}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

