app.get("/admin/customer-stats/data", async (req, res) => {
  try {
    const { pageKey, startDate, endDate } = req.query;
    const client = await connectDB();
    const db = client.db("chatbot");

    // Parse date filters (normalize to Bangkok time)
    const { startMoment, endMoment } = parseCustomerStatsDateRange(
      startDate,
      endDate,
    );
    const dateStart = startMoment.toDate();
    const dateEnd = endMoment.toDate();
    const startDateKey = startMoment.format("YYYY-MM-DD");
    const endDateKey = endMoment.format("YYYY-MM-DD");

    // Parse pageKey to get platform and botId
    let filterPlatform = null;
    let filterBotId = null;
    let orderBotIdCondition = null;
    let isDefaultPageBot = false;
    if (pageKey) {
      const parsed = parseOrderPageKey(pageKey);
      filterPlatform = parsed.platform;
      filterBotId = parsed.botId;
      orderBotIdCondition = buildOrderBotIdMatchCondition(filterBotId);
      isDefaultPageBot = !!(parsed.platform && parsed.botId === null);
    }

    // Build base query for orders
    const orderQuery = {
      extractedAt: { $gte: dateStart, $lte: dateEnd }
    };
    if (filterPlatform) orderQuery.platform = filterPlatform;
    if (orderBotIdCondition) {
      orderQuery.botId = orderBotIdCondition;
    } else if (isDefaultPageBot) {
      orderQuery.$or = [
        { botId: null },
        { botId: { $exists: false } },
        { botId: "" },
      ];
    }

    // Build base query for chat history
    const chatQuery = {
      timestamp: { $gte: dateStart, $lte: dateEnd },
      role: "user"
    };
    if (filterPlatform) chatQuery.platform = filterPlatform;
    if (filterBotId) {
      chatQuery.botId = filterBotId;
    } else if (isDefaultPageBot) {
      chatQuery.$or = [
        { botId: null },
        { botId: { $exists: false } },
        { botId: "" },
      ];
    }

    // Get orders
    const orders = await db.collection("orders").find(orderQuery).toArray();

    // Get chat messages for hourly distribution
    const chatMessages = await db.collection("chat_history")
      .find(chatQuery)
      .project({ senderId: 1, timestamp: 1 })
      .toArray();

    // Calculate overview stats
    const uniqueUsers = new Set(
      chatMessages.map((m) => m.senderId || m.userId).filter(Boolean),
    );
    const totalActiveUsers = uniqueUsers.size;
    const totalMessages = chatMessages.length;

    // Find new users (first message in the period)
    const userFirstMessages = {};
    chatMessages.forEach(m => {
      const senderId = m.senderId || m.userId;
      if (!senderId) return;
      const ts = getBangkokMoment(m.timestamp).valueOf();
      if (!userFirstMessages[senderId] || ts < userFirstMessages[senderId]) {
        userFirstMessages[senderId] = ts;
      }
    });

    // Check if user had messages before dateStart
    const allUserIds = [...uniqueUsers];
    let newUsers = 0;
    if (allUserIds.length > 0) {
      const existingMatch = {
        senderId: { $in: allUserIds },
        timestamp: { $lt: dateStart },
        role: "user",
      };
      if (filterPlatform) existingMatch.platform = filterPlatform;
      if (filterBotId) {
        existingMatch.botId = filterBotId;
      } else if (isDefaultPageBot) {
        existingMatch.$or = [
          { botId: null },
          { botId: { $exists: false } },
          { botId: "" },
        ];
      }

      const existingUsers = await db.collection("chat_history")
        .aggregate([
          {
            $match: existingMatch
          },
          { $group: { _id: "$senderId" } }
        ])
        .toArray();
      const existingUserIds = new Set(existingUsers.map(u => u._id));
      newUsers = allUserIds.filter(id => !existingUserIds.has(id)).length;
    }

    // Calculate sales stats
    const uniqueBuyers = new Set(
      orders.map((o) => o.userId).filter(Boolean),
    ).size;
    const totalOrders = orders.length;
    const pendingOrders = orders.filter(o => o.status === "pending").length;
    const confirmedOrders = orders.filter(o => o.status === "confirmed").length;
    const shippedOrders = orders.filter(o => o.status === "shipped").length;
    const completedOrders = orders.filter(o => o.status === "completed").length;
    const cancelledOrders = orders.filter(o => o.status === "cancelled").length;

    let totalSales = 0;
    let totalSalesConfirmed = 0;
    let totalShipping = 0;
    orders.forEach(order => {
      const orderData = order.orderData || {};
      const items = Array.isArray(orderData.items) ? orderData.items : [];
      let orderTotal = 0;
      items.forEach(item => {
        orderTotal += (parseFloat(item.price) || 0) * (parseInt(item.quantity) || 0);
      });
      totalSales += orderTotal;
      if (order.status === "confirmed") {
        totalSalesConfirmed += orderTotal;
      }
      totalShipping += parseFloat(orderData.shippingCost) || 0;
    });

    // Calculate conversion rates
    const conversionRate = totalActiveUsers > 0 ? (uniqueBuyers / totalActiveUsers * 100) : 0;
    const orderConfirmationRate = totalOrders > 0 ? ((confirmedOrders + shippedOrders + completedOrders) / totalOrders * 100) : 0;
    const orderCompletionRate = totalOrders > 0 ? (completedOrders / totalOrders * 100) : 0;
    const avgOrderValue = totalOrders > 0 ? Math.round(totalSales / totalOrders) : 0;
    const avgCustomerValue = uniqueBuyers > 0 ? Math.round(totalSales / uniqueBuyers) : 0;

    // Calculate hourly message distribution (3 modes: all, buyers, non-buyers)
    const buyerUserIds = new Set(
      orders.map((o) => o.userId).filter(Boolean),
    );

    const hourlyAll = Array.from({ length: 24 }, () => new Set());
    const hourlyBuyers = Array.from({ length: 24 }, () => new Set());
    const hourlyNonBuyers = Array.from({ length: 24 }, () => new Set());

    chatMessages.forEach((m) => {
      const senderId = m.senderId || m.userId;
      if (!senderId) return;
      const ts = getBangkokMoment(m.timestamp);
      const hour = ts.hour();
      const dateKey = ts.format("YYYY-MM-DD");
      const userDayKey = `${dateKey}:${senderId}`;

      hourlyAll[hour].add(userDayKey);
      if (buyerUserIds.has(senderId)) {
        hourlyBuyers[hour].add(userDayKey);
      } else {
        hourlyNonBuyers[hour].add(userDayKey);
      }
    });

    const hourlyMessages = {
      all: hourlyAll.map(set => set.size),
      buyers: hourlyBuyers.map(set => set.size),
      nonBuyers: hourlyNonBuyers.map(set => set.size)
    };

    const normalizeTrendUserId = (value) => {
      if (value === null || value === undefined) return "";
      return String(value).trim();
    };

    const isSingleDayRange = startDateKey === endDateKey;
    let closingRateTrend = {
      mode: isSingleDayRange ? "hourly" : "daily",
      points: [],
      totalUsers: totalActiveUsers,
      buyerUsers: uniqueBuyers,
      overallRate: Number(conversionRate.toFixed(1))
    };

    if (isSingleDayRange) {
      const totalUsersByHour = Array.from({ length: 24 }, () => new Set());
      const buyerUsersByHour = Array.from({ length: 24 }, () => new Set());

      chatMessages.forEach((message) => {
        const senderId = normalizeTrendUserId(message.senderId || message.userId);
        if (!senderId) return;
        const hour = getBangkokMoment(message.timestamp).hour();
        totalUsersByHour[hour].add(senderId);
      });

      orders.forEach((order) => {
        const userId = normalizeTrendUserId(order.userId);
        if (!userId) return;
        const hour = getBangkokMoment(
          order.extractedAt || order.createdAt || order.updatedAt || dateStart,
        ).hour();
        buyerUsersByHour[hour].add(userId);
      });

      closingRateTrend.points = Array.from({ length: 24 }, (_, hour) => {
        const totalUsersInHour = totalUsersByHour[hour].size;
        const buyerUsersInHour = buyerUsersByHour[hour].size;
        const closeRate = totalUsersInHour > 0
          ? (buyerUsersInHour / totalUsersInHour) * 100
          : 0;

        return {
          key: String(hour).padStart(2, "0"),
          label: String(hour).padStart(2, "0"),
          totalUsers: totalUsersInHour,
          buyerUsers: buyerUsersInHour,
          closeRate: Number(closeRate.toFixed(1))
        };
      });
    } else {
      const totalUsersByDay = new Map();
      const buyerUsersByDay = new Map();

      const getSetForDate = (sourceMap, key) => {
        if (!sourceMap.has(key)) {
          sourceMap.set(key, new Set());
        }
        return sourceMap.get(key);
      };

      chatMessages.forEach((message) => {
        const senderId = normalizeTrendUserId(message.senderId || message.userId);
        if (!senderId) return;
        const dateKey = getBangkokMoment(message.timestamp).format("YYYY-MM-DD");
        if (dateKey < startDateKey || dateKey > endDateKey) return;
        getSetForDate(totalUsersByDay, dateKey).add(senderId);
      });

      orders.forEach((order) => {
        const userId = normalizeTrendUserId(order.userId);
        if (!userId) return;
        const dateKey = getBangkokMoment(
          order.extractedAt || order.createdAt || order.updatedAt || dateStart,
        ).format("YYYY-MM-DD");
        if (dateKey < startDateKey || dateKey > endDateKey) return;
        getSetForDate(buyerUsersByDay, dateKey).add(userId);
      });

      const points = [];
      const cursor = startMoment.clone().startOf("day");
      while (cursor.isSameOrBefore(endMoment, "day")) {
        const dateKey = cursor.format("YYYY-MM-DD");
        const totalUsersInDay = (totalUsersByDay.get(dateKey) || new Set()).size;
        const buyerUsersInDay = (buyerUsersByDay.get(dateKey) || new Set()).size;
        const closeRate = totalUsersInDay > 0
          ? (buyerUsersInDay / totalUsersInDay) * 100
          : 0;

        points.push({
          key: dateKey,
          label: cursor.format("DD/MM"),
          totalUsers: totalUsersInDay,
          buyerUsers: buyerUsersInDay,
          closeRate: Number(closeRate.toFixed(1))
        });
        cursor.add(1, "day");
      }
      closingRateTrend.points = points;
    }

    // Get follow-up stats
    const followUpQuery = {
      dateKey: { $gte: startDateKey, $lte: endDateKey }
    };
    if (filterPlatform) followUpQuery.platform = filterPlatform;
    if (filterBotId) followUpQuery.botId = normalizeFollowUpBotId(filterBotId);

    const followUpTasks = await db.collection("follow_up_tasks").find(followUpQuery).toArray();
    const followUpActive = followUpTasks.filter(
      (t) => t.canceled !== true && t.completed !== true && t.status !== "failed",
    ).length;
    const followUpCompleted = followUpTasks.filter((t) => t.completed === true).length;
    const followUpCanceled = followUpTasks.filter((t) => t.canceled === true).length;
    const followUpFailed = followUpTasks.filter((t) => {
      if (t.status === "failed") return true;
      if (t.cancelReason === "send_failed") return true;
      const rounds = Array.isArray(t.rounds) ? t.rounds : [];
      return rounds.some((r) => r?.status === "failed");
    }).length;

    // Calculate payment methods
    let codCount = 0;
    let transferCount = 0;
    let otherCount = 0;
    orders.forEach(order => {
      const payment = (order.orderData?.paymentMethod || "").toLowerCase();
      if (payment.includes("ปลายทาง") || payment.includes("cod")) {
        codCount++;
      } else if (payment.includes("โอน") || payment.includes("transfer")) {
        transferCount++;
      } else if (payment) {
        otherCount++;
      }
    });

    // Calculate top products
    const productStats = {};
    orders.forEach(order => {
      const items = Array.isArray(order.orderData?.items) ? order.orderData.items : [];
      items.forEach(item => {
        const name = item.product || "ไม่ระบุ";
        if (!productStats[name]) {
          productStats[name] = { name, quantity: 0, revenue: 0 };
        }
        productStats[name].quantity += parseInt(item.quantity) || 0;
        productStats[name].revenue += (parseFloat(item.price) || 0) * (parseInt(item.quantity) || 0);
      });
    });
    const topProducts = Object.values(productStats)
      .sort((a, b) => b.revenue - a.revenue)
      .slice(0, 5);

    // Calculate top customers
    const customerStats = {};
    orders.forEach(order => {
      const userId = order.userId;
      if (!userId) return;
      if (!customerStats[userId]) {
        customerStats[userId] = {
          userId,
          name: order.orderData?.customerName || null,
          orderCount: 0,
          totalSpent: 0
        };
      }
      customerStats[userId].orderCount++;
      const items = Array.isArray(order.orderData?.items) ? order.orderData.items : [];
      items.forEach(item => {
        customerStats[userId].totalSpent += (parseFloat(item.price) || 0) * (parseInt(item.quantity) || 0);
      });
    });

    // Get display names for top customers
    const topCustomersRaw = Object.values(customerStats)
      .sort((a, b) => b.totalSpent - a.totalSpent)
      .slice(0, 5);

    const customerUserIds = topCustomersRaw.map(c => c.userId).filter(Boolean);
    let profileMap = {};
    if (customerUserIds.length > 0) {
      const profiles = await db.collection("user_profiles")
        .find({ userId: { $in: customerUserIds } })
        .project({ userId: 1, displayName: 1 })
        .toArray();
      profiles.forEach(p => {
        profileMap[p.userId] = p.displayName;
      });
    }

    const topCustomers = topCustomersRaw.map(c => ({
      ...c,
      name: c.name || profileMap[c.userId] || c.userId?.substring(0, 12) || "ไม่ระบุ"
    }));

    res.json({
      success: true,
      data: {
        overview: {
          newUsers,
          totalActiveUsers,
          totalMessages
        },
        sales: {
          uniqueBuyers,
          totalOrders,
          pendingOrders,
          confirmedOrders,
          shippedOrders,
          completedOrders,
          cancelledOrders,
          totalSales: Math.round(totalSales),
          totalSalesConfirmed: Math.round(totalSalesConfirmed),
          totalShipping: Math.round(totalShipping)
        },
        conversion: {
          conversionRate,
          orderConfirmationRate,
          orderCompletionRate,
          avgOrderValue,
          avgCustomerValue
        },
        followUp: {
          active: followUpActive,
          completed: followUpCompleted,
          canceled: followUpCanceled,
          failed: followUpFailed
        },
        hourlyMessages,
        closingRateTrend,
        topProducts,
        topCustomers,
        paymentMethods: {
          cod: codCount,
          transfer: transferCount,
          other: otherCount
        }
      }
    });
  } catch (error) {
    console.error("[CustomerStats] ไม่สามารถดึงข้อมูลสถิติได้:", error);
    res.json({ success: false, error: error.message });
  }
});

async function buildNativeOrderPagesResponse() {
  const [lineBots, facebookBots, instagramBots, whatsappBots, orderGroups] =
    await Promise.all([
      maybeListAppDocumentPayloads("line_bots", { limit: 1000 }),
      maybeListAppDocumentPayloads("facebook_bots", { limit: 1000 }),
      maybeListAppDocumentPayloads("instagram_bots", { limit: 1000 }),
      maybeListAppDocumentPayloads("whatsapp_bots", { limit: 1000 }),
      postgresNativeReadRepository.queryOrderPageGroups(),
    ]);

  const pageMap = new Map();
  const readDocId = (doc) => doc?._id?.toString?.() || doc?._id || doc?.id || "";
  const upsertPage = ({
    platform,
    botId = null,
    name = "",
    orderCount = 0,
    lastOrderAt = null,
  }) => {
    const normalizedPlatform = normalizeOrderPlatform(platform);
    const normalizedBotId = normalizeOrderBotId(botId);
    const pageKey = buildOrderPageKey(normalizedPlatform, normalizedBotId);
    const existing = pageMap.get(pageKey);

    if (existing) {
      if (name && !existing.name) existing.name = name;
      if (Number.isFinite(orderCount)) {
        existing.orderCount = Math.max(existing.orderCount || 0, orderCount);
      }
      if (lastOrderAt) {
        const existingTime = existing.lastOrderAt
          ? new Date(existing.lastOrderAt).getTime()
          : 0;
        const nextTime = new Date(lastOrderAt).getTime();
        if (nextTime > existingTime) {
          existing.lastOrderAt = lastOrderAt;
        }
      }
      return;
    }

    pageMap.set(pageKey, {
      pageKey,
      platform: normalizedPlatform,
      botId: normalizedBotId,
      name,
      orderCount: Number.isFinite(orderCount) ? orderCount : 0,
      lastOrderAt: lastOrderAt || null,
    });
  };

  lineBots.forEach((bot) => {
    const botId = readDocId(bot);
    if (!botId) return;
    upsertPage({
      platform: "line",
      botId,
      name:
        bot.displayName ||
        bot.name ||
        bot.botName ||
        `LINE Bot (${String(botId).slice(-4)})`,
    });
  });
  facebookBots.forEach((bot) => {
    const botId = readDocId(bot);
    if (!botId) return;
    upsertPage({
      platform: "facebook",
      botId,
      name:
        bot.pageName ||
        bot.name ||
        `Facebook Page (${String(botId).slice(-4)})`,
    });
  });
  instagramBots.forEach((bot) => {
    const botId = readDocId(bot);
    if (!botId) return;
    upsertPage({
      platform: "instagram",
      botId,
      name:
        bot.name ||
        bot.instagramUsername ||
        bot.instagramUserId ||
        bot.igUserId ||
        `Instagram (${String(botId).slice(-4)})`,
    });
  });
  whatsappBots.forEach((bot) => {
    const botId = readDocId(bot);
    if (!botId) return;
    upsertPage({
      platform: "whatsapp",
      botId,
      name:
        bot.name ||
        bot.phoneNumber ||
        bot.phoneNumberId ||
        `WhatsApp (${String(botId).slice(-4)})`,
    });
  });

  orderGroups.forEach((entry) => {
    const platform = normalizeOrderPlatform(entry.platform || "line");
    const botId = normalizeOrderBotId(entry.botId || null);
    const platformLabel = getPlatformLabel(platform);
    upsertPage({
      platform,
      botId,
      name: botId
        ? `${platformLabel} (${String(botId).slice(-4)})`
        : `${platformLabel} (default)`,
      orderCount: Number(entry.orderCount) || 0,
      lastOrderAt: entry.lastOrderAt || null,
    });
  });

  const pages = Array.from(pageMap.values()).sort((a, b) => {
    const orderDiff = (b.orderCount || 0) - (a.orderCount || 0);
    if (orderDiff !== 0) return orderDiff;
    return String(a.name || a.pageKey).localeCompare(
      String(b.name || b.pageKey),
      "th",
      { sensitivity: "base" },
    );
  });

  return {
    success: true,
    pages,
    settings: {
      schedulingEnabled: false,
      defaultCutoffTime: "00:00",
      extractionMode: "realtime",
    },
  };
}

app.get("/admin/orders/pages", async (req, res) => {
  try {
    if (isPostgresNativeReadEnabled()) {
      const cachedResponse = await getCachedAdminJson(
        req,
        ["orders-pages"],
        buildNativeOrderPagesResponse,
        { ttlSeconds: runtimeConfig.redis.adminCacheTtlSeconds },
      );
      return res.json(cachedResponse);
    }

    const client = await connectDB();
    const db = client.db("chatbot");

    const [lineBots, facebookBots, instagramBots, whatsappBots, orderGroups] =
      await Promise.all([
      db
        .collection("line_bots")
        .find({})
        .project({ name: 1, displayName: 1, botName: 1 })
        .toArray(),
      db
        .collection("facebook_bots")
        .find({})
        .project({ name: 1, pageName: 1 })
        .toArray(),
      db
        .collection("instagram_bots")
        .find({})
        .project({ name: 1, instagramUsername: 1, instagramUserId: 1, igUserId: 1 })
        .toArray(),
      db
        .collection("whatsapp_bots")
        .find({})
        .project({ name: 1, phoneNumber: 1, phoneNumberId: 1 })
        .toArray(),
      db
        .collection("orders")
        .aggregate([
          {
            $project: {
              platform: {
                $toLower: { $ifNull: ["$platform", "line"] },
              },
              botIdText: {
                $trim: {
                  input: {
                    $convert: {
                      input: "$botId",
                      to: "string",
                      onError: "",
                      onNull: "",
                    },
                  },
                },
              },
              extractedAt: "$extractedAt",
            },
          },
          {
            $group: {
              _id: {
                platform: "$platform",
                botIdText: "$botIdText",
              },
              orderCount: { $sum: 1 },
              lastOrderAt: { $max: "$extractedAt" },
            },
          },
        ])
        .toArray(),
      ]);

    const pageMap = new Map();

    const upsertPage = ({
      platform,
      botId = null,
      name = "",
      orderCount = 0,
      lastOrderAt = null,
    }) => {
      const normalizedPlatform = normalizeOrderPlatform(platform);
      const normalizedBotId = normalizeOrderBotId(botId);
      const pageKey = buildOrderPageKey(normalizedPlatform, normalizedBotId);
      const existing = pageMap.get(pageKey);

      if (existing) {
        if (name && !existing.name) existing.name = name;
        if (Number.isFinite(orderCount)) {
          existing.orderCount = Math.max(existing.orderCount || 0, orderCount);
        }
        if (lastOrderAt) {
          const existingTime = existing.lastOrderAt
            ? new Date(existing.lastOrderAt).getTime()
            : 0;
          const nextTime = new Date(lastOrderAt).getTime();
          if (nextTime > existingTime) {
            existing.lastOrderAt = lastOrderAt;
          }
        }
        return;
      }

      pageMap.set(pageKey, {
        pageKey,
        platform: normalizedPlatform,
        botId: normalizedBotId,
        name,
        orderCount: Number.isFinite(orderCount) ? orderCount : 0,
        lastOrderAt: lastOrderAt || null,
      });
    };

    lineBots.forEach((bot) => {
      const botId = bot?._id?.toString?.() || null;
      if (!botId) return;
      const label =
        bot.displayName ||
        bot.name ||
        bot.botName ||
        `LINE Bot (${botId.slice(-4)})`;
      upsertPage({
        platform: "line",
        botId,
        name: label,
      });
    });

    facebookBots.forEach((bot) => {
      const botId = bot?._id?.toString?.() || null;
      if (!botId) return;
      const label =
        bot.pageName ||
        bot.name ||
        `Facebook Page (${botId.slice(-4)})`;
      upsertPage({
        platform: "facebook",
        botId,
        name: label,
      });
    });

    instagramBots.forEach((bot) => {
      const botId = bot?._id?.toString?.() || null;
      if (!botId) return;
      const label =
        bot.name ||
        bot.instagramUsername ||
        bot.instagramUserId ||
        bot.igUserId ||
        `Instagram (${botId.slice(-4)})`;
      upsertPage({
        platform: "instagram",
        botId,
        name: label,
      });
    });

    whatsappBots.forEach((bot) => {
      const botId = bot?._id?.toString?.() || null;
      if (!botId) return;
      const label =
        bot.name ||
        bot.phoneNumber ||
        bot.phoneNumberId ||
        `WhatsApp (${botId.slice(-4)})`;
      upsertPage({
        platform: "whatsapp",
        botId,
        name: label,
      });
    });

    orderGroups.forEach((entry) => {
      const platform = normalizeOrderPlatform(entry?._id?.platform || "line");
      const botId = normalizeOrderBotId(entry?._id?.botIdText || null);
      const platformLabel = getPlatformLabel(platform);
      const fallbackName = botId
        ? `${platformLabel} (${botId.slice(-4)})`
        : `${platformLabel} (default)`;
      upsertPage({
        platform,
        botId,
        name: fallbackName,
        orderCount: Number(entry?.orderCount) || 0,
        lastOrderAt: entry?.lastOrderAt || null,
      });
    });

    const pages = Array.from(pageMap.values())
      .sort((a, b) => {
        const orderDiff = (b.orderCount || 0) - (a.orderCount || 0);
        if (orderDiff !== 0) return orderDiff;
        return String(a.name || a.pageKey).localeCompare(
          String(b.name || b.pageKey),
          "th",
          { sensitivity: "base" },
        );
      });

    res.json({
      success: true,
      pages,
      settings: {
        schedulingEnabled: false,
        defaultCutoffTime: "00:00",
        extractionMode: "realtime",
      },
    });
  } catch (error) {
    console.error("[Orders] ไม่สามารถดึงรายการเพจ/บอทได้:", error);
    res.status(500).json({
      success: false,
      error: error.message || "ไม่สามารถดึงรายการเพจได้",
      pages: [],
      settings: {
        schedulingEnabled: false,
        defaultCutoffTime: "00:00",
        extractionMode: "realtime",
      },
    });
  }
});


