// Send message as admin (AI assistant)
app.post("/admin/chat/send", async (req, res) => {
  try {
    const { userId, message } = req.body;

    if (!userId || !message) {
      return res.json({ success: false, error: "ข้อมูลไม่ครบถ้วน" });
    }

    // ตรวจจับคำสั่งควบคุมจากแอดมิน
    const trimmed = String(message).trim();

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("chat_history");

    // Determine platform and bot from latest chat
    const lastChat = await coll.findOne(
      buildChatHistoryUserMatch(userId),
      { sort: { timestamp: -1 } },
    );
    const platform = lastChat?.platform || "line";
    const botId = lastChat?.botId || null;

    // ดึงข้อมูล bot เพื่อตรวจสอบ keyword settings
    let keywordSettings = {};
    if (botId) {
      const botColl = db.collection(getBotCollectionName(platform));
      const botQuery = ObjectId.isValid(botId)
        ? { _id: new ObjectId(botId) }
        : { _id: botId };
      const bot = await botColl.findOne(botQuery);
      if (bot && bot.keywordSettings) {
        keywordSettings = bot.keywordSettings;
      }
    }

    // ตรวจสอบ keyword actions ก่อน (เช่น เปิด/ปิด AI, ปิดระบบติดตาม)
    const keywordResult = await detectKeywordAction(
      trimmed,
      keywordSettings,
      userId,
      platform,
      botId,
      true, // isFromAdmin = true
    );

    if (keywordResult.action) {
      // ถ้ามี keyword action และต้องการส่งข้อความตอบกลับ
      if (keywordResult.sendResponse && keywordResult.message) {
        if (platform === "facebook") {
          try {
            if (botId) {
              const fbBot = await findBotById(db, "facebook", botId);
              if (fbBot?.accessToken) {
                await sendFacebookMessage(
                  userId,
                  keywordResult.message,
                  fbBot.accessToken,
                  { metadata: "keyword_control_auto" },
                );
              } else {
                console.warn(
                  `[Admin Chat] ไม่พบ accessToken สำหรับ Facebook bot ${botId} ขณะส่งข้อความยืนยัน keyword`,
                );
              }
            } else {
              console.warn(
                `[Admin Chat] ไม่พบ botId สำหรับผู้ใช้ ${userId} ขณะส่งข้อความยืนยัน keyword`,
              );
            }
          } catch (controlReplyErr) {
            console.error(
              `[Admin Chat] ส่งข้อความยืนยัน keyword ไป Facebook ไม่สำเร็จ:`,
              controlReplyErr?.message || controlReplyErr,
            );
          }
        }

        const controlDoc = {
          senderId: userId,
          role: "assistant",
          content: `[ระบบ] ${keywordResult.message}`,
          timestamp: new Date(),
          source: "admin_chat",
          platform,
          botId,
        };
        const controlInsertResult = await coll.insertOne(controlDoc);
        if (controlInsertResult?.insertedId) {
          controlDoc._id = controlInsertResult.insertedId;
        }
        await maybeMirrorChatMessage(controlDoc, "adminChat:keywordControl");
        await resetUserUnreadCount(userId);

        // Emit เพื่ออัปเดต UI ของแอดมิน
        io.to("admin").emit("newMessage", {
          userId: userId,
          message: controlDoc,
          sender: "assistant",
          timestamp: controlDoc.timestamp,
        });

        return res.json({
          success: true,
          control: true,
          displayMessage: keywordResult.message,
          skipEcho: true,
        });
      } else {
        // ไม่ส่งข้อความตอบกลับ แต่ดำเนินการสำเร็จ
        return res.json({
          success: true,
          control: true,
          displayMessage: "ดำเนินการเรียบร้อยแล้ว (ไม่ส่งข้อความตอบกลับ)",
          skipEcho: true,
          silent: true,
        });
      }
    }

    // กรณีเป็นคำสั่ง [ปิด] / [เปิด] (legacy)
    if (trimmed === "[ปิด]" || trimmed === "[เปิด]") {
      const enable = trimmed === "[เปิด]";
      await setUserStatus(userId, enable);

      const controlText = enable
        ? "เปิด AI สำหรับผู้ใช้นี้แล้ว"
        : "ปิด AI สำหรับผู้ใช้นี้ชั่วคราวแล้ว";
      const controlDoc = {
        senderId: userId,
        role: "assistant",
        content: `[ระบบ] ${controlText}`,
        timestamp: new Date(),
        source: "admin_chat",
        platform,
        botId,
      };
      const legacyControlInsert = await coll.insertOne(controlDoc);
      if (legacyControlInsert?.insertedId) {
        controlDoc._id = legacyControlInsert.insertedId;
      }
      await maybeMirrorChatMessage(controlDoc, "adminChat:legacyControl");

      // รีเซ็ต unread count เมื่อแอดมินตอบกลับ
      await resetUserUnreadCount(userId);

      // ไม่ส่งข้อความควบคุมไปยังผู้ใช้

      // Emit เพื่ออัปเดต UI ของแอดมิน
      io.to("admin").emit("newMessage", {
        userId: userId,
        message: controlDoc,
        sender: "assistant",
        timestamp: controlDoc.timestamp,
      });

      return res.json({
        success: true,
        control: true,
        displayMessage: controlText,
        skipEcho: true,
      });
    }

    const createAdminMessageDoc = () => ({
      senderId: userId,
      role: "assistant",
      content: message,
      timestamp: new Date(),
      source: "admin_chat",
      platform,
      botId,
    });

    const saveAndEmitAdminMessage = async (doc) => {
      const insertResult = await coll.insertOne(doc);
      if (insertResult?.insertedId) {
        doc._id = insertResult.insertedId;
      }
      await maybeMirrorChatMessage(doc, "adminChat:assistant");
      await resetUserUnreadCount(userId);
      io.to("admin").emit("newMessage", {
        userId,
        message: doc,
        sender: "assistant",
        timestamp: doc.timestamp,
      });
      return doc;
    };

    // ส่งต่อไปยังแพลตฟอร์มของผู้ใช้ (และหลีกเลี่ยงการบันทึกซ้ำในกรณี Facebook เพื่อกันแสดงซ้ำ)
    if (platform === "facebook") {
      try {
        if (botId) {
          const fbBot = await findBotById(db, "facebook", botId);
          if (fbBot) {
            await sendFacebookMessage(userId, message, fbBot.accessToken, {
              metadata: "admin_manual",
            });
            console.log(
              `[Admin Chat] ส่งข้อความไปยัง Facebook user ${userId}: ${message.substring(0, 50)}...`,
            );
            // ไม่ insert messageDoc และไม่ emit ที่นี่ ให้รอ Facebook echo บันทึกและกระจาย UI แทน
            return res.json({ success: true, skipEcho: true });
          }
        }
        // ถ้าไม่มี fbBot ให้ถือว่าไม่สามารถส่งได้
        return res.json({
          success: false,
          error: "ไม่พบ Facebook Bot สำหรับผู้ใช้นี้",
        });
      } catch (fbError) {
        console.log(
          `[Admin Chat] ไม่สามารถส่งไปยัง Facebook ได้: ${fbError.message}`,
        );
        return res.json({
          success: false,
          error: "ไม่สามารถส่งไปยัง Facebook ได้",
        });
      }
    }

    if (platform === "instagram") {
      try {
        if (!botId) {
          return res.json({
            success: false,
            error: "ไม่พบ Instagram Bot สำหรับผู้ใช้นี้",
          });
        }
        const igBot = await findBotById(db, "instagram", botId);
        const accessToken = resolveMetaAccessToken(igBot || {});
        const instagramSenderId = resolveInstagramSenderId(igBot || {});
        if (!igBot || !accessToken || !instagramSenderId) {
          return res.json({
            success: false,
            error: "ไม่พบข้อมูล Instagram Bot สำหรับผู้ใช้นี้",
          });
        }

        await sendInstagramMessage(
          userId,
          message,
          accessToken,
          instagramSenderId,
          {
            selectedImageCollections: igBot.selectedImageCollections || null,
          },
        );
        const messageDoc = await saveAndEmitAdminMessage(createAdminMessageDoc());
        return res.json({ success: true, message: messageDoc });
      } catch (igError) {
        console.log(
          `[Admin Chat] ไม่สามารถส่งไปยัง Instagram ได้: ${igError.message}`,
        );
        return res.json({
          success: false,
          error: "ไม่สามารถส่งไปยัง Instagram ได้",
        });
      }
    }

    if (platform === "whatsapp") {
      try {
        if (!botId) {
          return res.json({
            success: false,
            error: "ไม่พบ WhatsApp Bot สำหรับผู้ใช้นี้",
          });
        }
        const waBot = await findBotById(db, "whatsapp", botId);
        const accessToken = resolveMetaAccessToken(waBot || {});
        const phoneNumberId = resolveWhatsAppPhoneNumberId(waBot || {});
        if (!waBot || !accessToken || !phoneNumberId) {
          return res.json({
            success: false,
            error: "ไม่พบข้อมูล WhatsApp Bot สำหรับผู้ใช้นี้",
          });
        }

        await sendWhatsAppMessage(userId, message, accessToken, phoneNumberId, {
          selectedImageCollections: waBot.selectedImageCollections || null,
        });
        const messageDoc = await saveAndEmitAdminMessage(createAdminMessageDoc());
        return res.json({ success: true, message: messageDoc });
      } catch (waError) {
        console.log(
          `[Admin Chat] ไม่สามารถส่งไปยัง WhatsApp ได้: ${waError.message}`,
        );
        return res.json({
          success: false,
          error: "ไม่สามารถส่งไปยัง WhatsApp ได้",
        });
      }
    }

    // LINE หรือแพลตฟอร์มอื่น: insert และ emit ตามปกติ
    const messageDoc = await saveAndEmitAdminMessage(createAdminMessageDoc());

    try {
      let lineClientForSend = null;
      let selectedImageCollections = null;

      if (botId) {
        const lineBot = await findBotById(db, "line", botId);
        if (lineBot) {
          if (lineBot.channelAccessToken && lineBot.channelSecret) {
            lineClientForSend = createLineClient(
              lineBot.channelAccessToken,
              lineBot.channelSecret,
            );
          }
          if (Array.isArray(lineBot.selectedImageCollections)) {
            selectedImageCollections = lineBot.selectedImageCollections;
          }
        }
      }

      if (!lineClientForSend) {
        lineClientForSend = await getLineClientForContext(botId);
      }

      if (!lineClientForSend) {
        throw new Error("ไม่พบ LINE client สำหรับผู้ใช้นี้");
      }

      const payloads = await buildLineMessagesFromTemplate(
        message,
        selectedImageCollections,
      );
      if (!payloads.length) {
        throw new Error("ไม่มีเนื้อหาสำหรับส่งไปยัง LINE");
      }

      await sendLineMessagesByChunks(lineClientForSend, userId, payloads);
      console.log(
        `[Admin Chat] ส่งข้อความไปยัง LINE user ${userId}: ${message.substring(0, 50)}...`,
      );
    } catch (lineError) {
      console.log(
        `[Admin Chat] ไม่สามารถส่งไปยัง LINE ได้: ${lineError.message}`,
      );
      // ไม่ return error เพราะข้อความยังบันทึกลง database ได้
    }

    res.json({ success: true, message: messageDoc });
  } catch (err) {
    console.error("Error sending admin message:", err);
    res.json({ success: false, error: err.message });
  }
});

