const TELEGRAM_API_BASE_URL = "https://api.telegram.org";

function normalizeUrlBase(value) {
  if (typeof value !== "string") return "";
  const trimmed = value.trim();
  if (!trimmed) return "";
  return trimmed.replace(/\/$/, "");
}

function isHttpsUrl(value) {
  if (typeof value !== "string") return false;
  return /^https:\/\//i.test(value);
}

function buildTelegramApiUrl(botToken, method) {
  const token = typeof botToken === "string" ? botToken.trim() : "";
  const methodName = typeof method === "string" ? method.trim() : "";
  if (!token || !methodName) return "";
  return `${TELEGRAM_API_BASE_URL}/bot${token}/${methodName}`;
}

function buildTelegramWebhookUrl(req, botId) {
  const base = normalizeUrlBase(
    process.env.PUBLIC_BASE_URL || `https://${req.get("host")}`,
  );
  if (!isHttpsUrl(base)) return "";
  return `${base}/webhook/telegram/${encodeURIComponent(botId)}`;
}

function generateTelegramWebhookSecret() {
  return crypto.randomBytes(24).toString("hex");
}

function normalizeTelegramBotName(value, fallback = "Telegram Bot") {
  const raw = typeof value === "string" ? value.trim() : "";
  return raw || fallback;
}

function normalizeTelegramBotStatus(value) {
  const normalized = typeof value === "string" ? value.trim().toLowerCase() : "";
  return normalized === "inactive" ? "inactive" : "active";
}

function resolveTelegramBotStatus({
  requestedStatus,
  requestedIsActive,
  fallbackStatus = "active",
} = {}) {
  if (typeof requestedIsActive === "boolean") {
    return requestedIsActive ? "active" : "inactive";
  }
  if (requestedStatus === "inactive" || requestedStatus === "active") {
    return requestedStatus;
  }
  return normalizeTelegramBotStatus(fallbackStatus);
}

function maskTelegramBotToken(token) {
  const normalized = typeof token === "string" ? token.trim() : "";
  if (!normalized) return "";
  if (normalized.length <= 6) return "••••";
  return `••••${normalized.slice(-6)}`;
}

function normalizeTelegramUsername(value) {
  if (typeof value !== "string") return "";
  return value.replace(/^@+/, "").trim();
}

function normalizeTelegramChatId(value) {
  if (typeof value === "string") return value.trim();
  if (typeof value === "number" && Number.isFinite(value)) return String(value);
  return "";
}

async function fetchTelegramBotProfile(botToken) {
  const url = buildTelegramApiUrl(botToken, "getMe");
  if (!url) throw new Error("INVALID_BOT_TOKEN");
  const response = await axios.post(
    url,
    {},
    {
      timeout: 15000,
    },
  );
  if (response?.data?.ok !== true || !response?.data?.result) {
    const description =
      response?.data?.description || "ไม่สามารถดึงข้อมูล Telegram Bot ได้";
    throw new Error(description);
  }
  return response.data.result;
}

async function setTelegramWebhook({
  botToken,
  webhookUrl,
  secretToken,
}) {
  const url = buildTelegramApiUrl(botToken, "setWebhook");
  if (!url || !webhookUrl || !secretToken) {
    throw new Error("SET_WEBHOOK_INPUT_INVALID");
  }

  const response = await axios.post(
    url,
    {
      url: webhookUrl,
      secret_token: secretToken,
      allowed_updates: [
        "message",
        "edited_message",
        "channel_post",
        "my_chat_member",
      ],
      drop_pending_updates: false,
    },
    { timeout: 20000 },
  );

  if (response?.data?.ok !== true) {
    const description =
      response?.data?.description || "ตั้งค่า Telegram webhook ไม่สำเร็จ";
    throw new Error(description);
  }

  return response.data.result || true;
}

async function deleteTelegramWebhook(botToken) {
  const url = buildTelegramApiUrl(botToken, "deleteWebhook");
  if (!url) return false;
  try {
    const response = await axios.post(
      url,
      { drop_pending_updates: false },
      { timeout: 10000 },
    );
    return response?.data?.ok === true;
  } catch (_) {
    return false;
  }
}

const NOTIFICATION_CHANNEL_TYPES = new Set(["line_group", "telegram_group"]);

function normalizeNotificationChannelType(value) {
  if (typeof value !== "string") return "line_group";
  const normalized = value.trim().toLowerCase();
  if (!normalized) return "line_group";
  return NOTIFICATION_CHANNEL_TYPES.has(normalized) ? normalized : "line_group";
}

function normalizeNotificationChannelSettings(settings, options = {}) {
  const raw = settings && typeof settings === "object" ? settings : {};
  const channelType = normalizeNotificationChannelType(options.channelType);
  const isLineGroup = channelType === "line_group";
  const includeCustomer = parseOptionalBoolean(raw.includeCustomer);
  const includeItemsCount = parseOptionalBoolean(raw.includeItemsCount);
  const includeItemsDetail = parseOptionalBoolean(raw.includeItemsDetail);
  const includeAddress = parseOptionalBoolean(raw.includeAddress);
  const includePhone = parseOptionalBoolean(raw.includePhone);
  const includePaymentMethod = parseOptionalBoolean(raw.includePaymentMethod);
  const includeTotalAmount = parseOptionalBoolean(raw.includeTotalAmount);
  const includeOrderLink = parseOptionalBoolean(raw.includeOrderLink);
  const slipOkEnabled = parseOptionalBoolean(raw.slipOkEnabled);

  const slipOkApiUrl =
    typeof raw.slipOkApiUrl === "string" ? raw.slipOkApiUrl.trim() : "";
  const slipOkApiKey =
    typeof raw.slipOkApiKey === "string" ? raw.slipOkApiKey.trim() : "";

  return {
    template: "simple",
    includeCustomer: includeCustomer !== false,
    includeItemsCount: includeItemsCount !== false,
    includeItemsDetail: includeItemsDetail !== false,
    includeAddress: includeAddress !== false,
    includePhone: includePhone !== false,
    includePaymentMethod: includePaymentMethod !== false,
    includeTotalAmount: includeTotalAmount !== false,
    includeOrderLink: includeOrderLink === true,
    slipOkEnabled: isLineGroup && slipOkEnabled === true,
    slipOkApiUrl: isLineGroup ? slipOkApiUrl : "",
    slipOkApiKey: isLineGroup ? slipOkApiKey : "",
  };
}

const NOTIFICATION_DELIVERY_MODES = new Set(["realtime", "scheduled"]);
const NOTIFICATION_SUMMARY_TIME_REGEX = /^([0-1]?\d|2[0-3])[:.]([0-5]\d)$/;

function normalizeNotificationDeliveryMode(value) {
  if (typeof value !== "string") return "realtime";
  const normalized = value.trim().toLowerCase();
  return NOTIFICATION_DELIVERY_MODES.has(normalized)
    ? normalized
    : "realtime";
}

function normalizeNotificationSummaryTime(value) {
  if (typeof value !== "string") return null;
  const match = value.trim().match(NOTIFICATION_SUMMARY_TIME_REGEX);
  if (!match) return null;
  const hours = match[1].padStart(2, "0");
  const minutes = match[2];
  return `${hours}:${minutes}`;
}

function normalizeNotificationSummaryTimes(values) {
  const list = [];
  if (Array.isArray(values)) {
    list.push(...values);
  } else if (typeof values === "string") {
    list.push(...values.split(/[,\s]+/));
  }

  const normalized = [];
  const seen = new Set();
  list.forEach((value) => {
    const parsed = normalizeNotificationSummaryTime(
      typeof value === "string" ? value : String(value || ""),
    );
    if (!parsed || seen.has(parsed)) return;
    seen.add(parsed);
    normalized.push(parsed);
  });

  normalized.sort((a, b) => {
    const [ah, am] = a.split(":").map((part) => parseInt(part, 10));
    const [bh, bm] = b.split(":").map((part) => parseInt(part, 10));
    return ah * 60 + am - (bh * 60 + bm);
  });

  return normalized;
}

const NOTIFICATION_SUMMARY_INTERVAL_MS = 60 * 1000;
let notificationSummaryTimer = null;
let notificationSummaryProcessing = false;

function getSummaryTimeMinutes(time) {
  const [hoursStr, minutesStr] = time.split(":");
  const hours = parseInt(hoursStr, 10);
  const minutes = parseInt(minutesStr, 10);
  if (Number.isNaN(hours) || Number.isNaN(minutes)) return null;
  return hours * 60 + minutes;
}

function getSummaryMomentForTime(time, baseMoment, timezone) {
  const tz = timezone || BANGKOK_TZ;
  const [hoursStr, minutesStr] = time.split(":");
  const hours = parseInt(hoursStr, 10);
  const minutes = parseInt(minutesStr, 10);
  if (Number.isNaN(hours) || Number.isNaN(minutes)) return null;
  const momentBase = baseMoment ? baseMoment.clone() : moment.tz(tz);
  return momentBase
    .clone()
    .hours(hours)
    .minutes(minutes)
    .seconds(0)
    .milliseconds(0);
}

function getLatestDueSummaryMoment(nowMoment, summaryTimes, timezone) {
  if (!summaryTimes.length) return null;
  let dueMoment = null;
  summaryTimes.forEach((time) => {
    const candidate = getSummaryMomentForTime(time, nowMoment, timezone);
    if (!candidate) return;
    if (nowMoment.isSameOrAfter(candidate)) {
      dueMoment = candidate;
    }
  });
  return dueMoment;
}

function getPreviousSummaryMoment(baseMoment, summaryTimes, timezone) {
  if (!baseMoment || !summaryTimes.length) return null;
  const baseMinutes = baseMoment.hours() * 60 + baseMoment.minutes();
  let previousTime = null;
  summaryTimes.forEach((time) => {
    const minutes = getSummaryTimeMinutes(time);
    if (minutes === null) return;
    if (minutes < baseMinutes) previousTime = time;
  });

  if (previousTime) {
    return getSummaryMomentForTime(previousTime, baseMoment, timezone);
  }

  const prevDay = baseMoment.clone().subtract(1, "day");
  const lastTime = summaryTimes[summaryTimes.length - 1];
  return getSummaryMomentForTime(lastTime, prevDay, timezone);
}

function buildSummarySlotKey(momentValue) {
  if (!momentValue) return "";
  return momentValue.format("YYYY-MM-DD|HH:mm");
}

async function evaluateNotificationSummarySchedules() {
  if (notificationSummaryProcessing) {
    return;
  }

  notificationSummaryProcessing = true;
  try {
    const client = await connectDB();
    const db = client.db("chatbot");
    const channels = await db
      .collection("notification_channels")
      .find({ isActive: true })
      .toArray();

    if (!channels.length) return;

    for (const channel of channels) {
      try {
        const channelType = normalizeNotificationChannelType(channel.type);
        if (!NOTIFICATION_CHANNEL_TYPES.has(channelType)) continue;
        const deliveryMode = normalizeNotificationDeliveryMode(
          channel.deliveryMode,
        );
        if (deliveryMode !== "scheduled") continue;

        const summaryTimes = normalizeNotificationSummaryTimes(
          channel.summaryTimes || [],
        );
        if (!summaryTimes.length) continue;

        const timezone = channel.summaryTimezone || BANGKOK_TZ;
        const nowMoment = moment.tz(timezone);
        const dueMoment = getLatestDueSummaryMoment(
          nowMoment,
          summaryTimes,
          timezone,
        );
        if (!dueMoment) continue;

        const slotKey = buildSummarySlotKey(dueMoment);
        if (channel.lastSummarySlotKey === slotKey) {
          continue;
        }

        let windowStartMoment = null;
        if (channel.lastSummaryAt) {
          const lastMoment = moment.tz(channel.lastSummaryAt, timezone);
          if (lastMoment.isValid()) {
            windowStartMoment = lastMoment;
          }
        }

        if (!windowStartMoment || windowStartMoment.isAfter(dueMoment)) {
          windowStartMoment = getPreviousSummaryMoment(
            dueMoment,
            summaryTimes,
            timezone,
          );
        }

        if (!windowStartMoment || !windowStartMoment.isValid()) {
          windowStartMoment = dueMoment.clone().startOf("day");
        }

        if (windowStartMoment.isSameOrAfter(dueMoment)) {
          windowStartMoment = dueMoment.clone().startOf("day");
        }

        if (windowStartMoment.isSameOrAfter(dueMoment)) {
          continue;
        }

        const result = await notificationService.sendOrderSummary(channel, {
          windowStart: windowStartMoment.toDate(),
          windowEnd: dueMoment.toDate(),
        });

        if (result?.success) {
          const updatedAt = new Date();
          await db.collection("notification_channels").updateOne(
            { _id: channel._id },
            {
              $set: {
                lastSummaryAt: dueMoment.toDate(),
                lastSummarySlotKey: slotKey,
                updatedAt,
              },
            },
          );
          await maybeMirrorAppDocumentFromCollection("notification_channels", {
            ...channel,
            lastSummaryAt: dueMoment.toDate(),
            lastSummarySlotKey: slotKey,
            updatedAt,
          });
        }
      } catch (channelError) {
        console.error(
          `[Notifications] Summary channel error:`,
          channelError?.message || channelError,
        );
      }
    }
  } catch (error) {
    console.error(
      "[Notifications] Summary schedule error:",
      error?.message || error,
    );
  } finally {
    notificationSummaryProcessing = false;
  }
}

async function startNotificationSummaryScheduler() {
  if (notificationSummaryTimer) {
    clearInterval(notificationSummaryTimer);
  }

  notificationSummaryTimer = setInterval(() => {
    evaluateNotificationSummarySchedules().catch((err) => {
      console.error(
        "[Notifications] Summary scheduler loop error:",
        err?.message || err,
      );
    });
  }, NOTIFICATION_SUMMARY_INTERVAL_MS);

  setTimeout(() => {
    evaluateNotificationSummarySchedules().catch((err) => {
      console.error(
        "[Notifications] Summary scheduler initial error:",
        err?.message || err,
      );
    });
  }, 5000);

  console.log(
    `[Notifications] Summary scheduler started (interval ${NOTIFICATION_SUMMARY_INTERVAL_MS / 1000}s)`,
  );
}

function normalizeNotificationSourcesInput(sources) {
  if (!Array.isArray(sources)) return [];
  const seen = new Set();
  const out = [];

  sources.forEach((source) => {
    const platform = normalizeOrderPlatform(source?.platform);
    const botId = normalizeOrderBotId(source?.botId);
    if (!botId) return;
    const key = `${platform}:${botId}`;
    if (seen.has(key)) return;
    seen.add(key);
    out.push({ platform, botId });
  });

  return out;
}

function mapNotificationChannelDoc(doc, ctx = {}) {
  const channelId = doc?._id?.toString?.() || "";
  const type = normalizeNotificationChannelType(doc?.type);

  const senderBotId = normalizeIdString(doc?.senderBotId || doc?.botId || "");
  const groupId = normalizeIdString(doc?.groupId || doc?.lineGroupId || "");
  const lineGroupKey = senderBotId && groupId ? `${senderBotId}:${groupId}` : null;
  const lineGroup = lineGroupKey ? ctx.lineGroupMap?.get(lineGroupKey) : null;

  const telegramBotId = normalizeIdString(doc?.telegramBotId || "");
  const telegramChatId = normalizeIdString(doc?.telegramChatId || "");
  const telegramGroupKey =
    telegramBotId && telegramChatId ? `${telegramBotId}:${telegramChatId}` : null;
  const telegramGroup = telegramGroupKey
    ? ctx.telegramGroupMap?.get(telegramGroupKey)
    : null;

  return {
    id: channelId,
    name: doc.name || "",
    type,
    senderBotId: type === "line_group" ? senderBotId || null : null,
    senderBotName:
      type === "line_group" && senderBotId
        ? ctx.lineBotMap?.get(senderBotId) || null
        : null,
    groupId: type === "line_group" ? groupId || null : null,
    groupName: type === "line_group" ? lineGroup?.groupName || null : null,
    groupStatus: type === "line_group" ? lineGroup?.status || null : null,
    sourceType: type === "line_group" ? lineGroup?.sourceType || null : null,
    telegramBotId: type === "telegram_group" ? telegramBotId || null : null,
    telegramBotName: type === "telegram_group" && telegramBotId
      ? ctx.telegramBotMap?.get(telegramBotId) || null
      : null,
    telegramChatId: type === "telegram_group" ? telegramChatId || null : null,
    telegramChatTitle: type === "telegram_group" ? telegramGroup?.title || null : null,
    telegramChatUsername:
      type === "telegram_group" ? telegramGroup?.username || null : null,
    telegramChatStatus: type === "telegram_group" ? telegramGroup?.status || null : null,
    receiveFromAllBots: doc.receiveFromAllBots === true,
    sources: normalizeNotificationSourcesInput(doc.sources || []),
    eventTypes: Array.isArray(doc.eventTypes) ? doc.eventTypes : ["new_order"],
    deliveryMode: normalizeNotificationDeliveryMode(doc.deliveryMode),
    summaryTimes: normalizeNotificationSummaryTimes(doc.summaryTimes || []),
    summaryTimezone: doc.summaryTimezone || BANGKOK_TZ,
    settings: normalizeNotificationChannelSettings(doc.settings || {}, { channelType: type }),
    isActive: doc.isActive === true,
    createdAt: doc.createdAt || null,
    updatedAt: doc.updatedAt || null,
  };
}

app.get("/admin/api/notification-channels", requireAdmin, async (req, res) => {
  try {
    const client = await connectDB();
    const db = client.db("chatbot");

    const channels = await db
      .collection("notification_channels")
      .find({})
      .sort({ createdAt: -1 })
      .toArray();

    const lineSenderBotIds = Array.from(
      new Set(
        channels
          .filter((ch) => normalizeNotificationChannelType(ch?.type) === "line_group")
          .map((ch) => ch.senderBotId || ch.botId || null)
          .filter(Boolean)
          .map((id) => String(id)),
      ),
    ).filter((id) => ObjectId.isValid(id));

    const telegramSenderBotIds = Array.from(
      new Set(
        channels
          .filter(
            (ch) => normalizeNotificationChannelType(ch?.type) === "telegram_group",
          )
          .map((ch) => ch.telegramBotId || null)
          .filter(Boolean)
          .map((id) => String(id)),
      ),
    ).filter((id) => ObjectId.isValid(id));

    const lineBotDocs = lineSenderBotIds.length
      ? await db
        .collection("line_bots")
        .find({ _id: { $in: lineSenderBotIds.map((id) => new ObjectId(id)) } })
        .project({ name: 1, displayName: 1, botName: 1 })
        .toArray()
      : [];

    const lineBotMap = new Map();
    lineBotDocs.forEach((bot) => {
      const label =
        bot.displayName ||
        bot.name ||
        bot.botName ||
        `LINE Bot (${bot._id.toString().slice(-4)})`;
      lineBotMap.set(bot._id.toString(), label);
    });

    const telegramBotDocs = telegramSenderBotIds.length
      ? await db
        .collection("telegram_notification_bots")
        .find({ _id: { $in: telegramSenderBotIds.map((id) => new ObjectId(id)) } })
        .project({ name: 1, botUsername: 1 })
        .toArray()
      : [];

    const telegramBotMap = new Map();
    telegramBotDocs.forEach((bot) => {
      const username =
        typeof bot?.botUsername === "string" && bot.botUsername.trim()
          ? `@${bot.botUsername.trim()}`
          : null;
      const label =
        bot.name ||
        username ||
        `Telegram Bot (${bot._id.toString().slice(-4)})`;
      telegramBotMap.set(bot._id.toString(), label);
    });

    const lineGroupDocs = lineSenderBotIds.length
      ? await db
        .collection("line_bot_groups")
        .find({ botId: { $in: lineSenderBotIds } })
        .project({ botId: 1, groupId: 1, groupName: 1, status: 1, sourceType: 1 })
        .toArray()
      : [];

    const lineGroupMap = new Map();
    lineGroupDocs.forEach((group) => {
      if (!group?.botId || !group?.groupId) return;
      lineGroupMap.set(`${group.botId}:${group.groupId}`, group);
    });

    const telegramGroupDocs = telegramSenderBotIds.length
      ? await db
        .collection("telegram_bot_groups")
        .find({ botId: { $in: telegramSenderBotIds } })
        .project({ botId: 1, chatId: 1, title: 1, username: 1, status: 1 })
        .toArray()
      : [];

    const telegramGroupMap = new Map();
    telegramGroupDocs.forEach((group) => {
      if (!group?.botId || !group?.chatId) return;
      telegramGroupMap.set(`${group.botId}:${group.chatId}`, group);
    });

    res.json({
      success: true,
      channels: channels.map((doc) =>
        mapNotificationChannelDoc(doc, {
          lineBotMap,
          lineGroupMap,
          telegramBotMap,
          telegramGroupMap,
        }),
      ),
    });
  } catch (err) {
    console.error("[Notifications] Error listing channels:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

app.post("/admin/api/notification-channels", requireAdmin, async (req, res) => {
  try {
    const name = typeof req.body?.name === "string" ? req.body.name.trim() : "";
    const channelType = normalizeNotificationChannelType(req.body?.type);
    const senderBotId =
      typeof req.body?.senderBotId === "string"
        ? req.body.senderBotId.trim()
        : "";
    const groupId =
      typeof req.body?.groupId === "string" ? req.body.groupId.trim() : "";
    const telegramBotId =
      typeof req.body?.telegramBotId === "string"
        ? req.body.telegramBotId.trim()
        : "";
    const telegramChatId =
      typeof req.body?.telegramChatId === "string"
        ? req.body.telegramChatId.trim()
        : "";

    if (!name) {
      return res.status(400).json({
        success: false,
        error: "กรุณากรอกชื่อช่องทางแจ้งเตือน",
      });
    }

    if (channelType === "line_group" && (!ObjectId.isValid(senderBotId) || !groupId)) {
      return res.status(400).json({
        success: false,
        error: "กรุณากรอก senderBotId และ groupId ให้ถูกต้องสำหรับ LINE",
      });
    }

    if (
      channelType === "telegram_group" &&
      (!ObjectId.isValid(telegramBotId) || !telegramChatId)
    ) {
      return res.status(400).json({
        success: false,
        error: "กรุณากรอก telegramBotId และ telegramChatId ให้ถูกต้อง",
      });
    }

    const receiveFromAllBots = parseOptionalBoolean(req.body?.receiveFromAllBots);
    const sources = normalizeNotificationSourcesInput(req.body?.sources || []);
    const settings = normalizeNotificationChannelSettings(req.body?.settings || {}, {
      channelType,
    });
    const isActive = parseOptionalBoolean(req.body?.isActive);
    const receiveAll = receiveFromAllBots !== false;
    const deliveryMode = normalizeNotificationDeliveryMode(
      req.body?.deliveryMode,
    );
    const summaryTimes = normalizeNotificationSummaryTimes(
      req.body?.summaryTimes,
    );

    if (!receiveAll && sources.length === 0) {
      return res.status(400).json({
        success: false,
        error: "กรุณาเลือกบอทต้นทางอย่างน้อย 1 รายการ หรือเลือก 'รับจากทุกบอท'",
      });
    }

    if (deliveryMode === "scheduled" && summaryTimes.length === 0) {
      return res.status(400).json({
        success: false,
        error: "กรุณาระบุเวลาสรุปอย่างน้อย 1 เวลา",
      });
    }

    const client = await connectDB();
    const db = client.db("chatbot");

    if (channelType === "line_group") {
      const senderBot = await db
        .collection("line_bots")
        .findOne({ _id: new ObjectId(senderBotId) }, { projection: { _id: 1 } });
      if (!senderBot) {
        return res.status(400).json({ success: false, error: "ไม่พบ LINE Bot ที่ระบุ" });
      }

      const group = await db.collection("line_bot_groups").findOne({
        botId: senderBotId,
        groupId,
        status: { $ne: "left" },
      });
      if (!group) {
        return res.status(400).json({
          success: false,
          error:
            "ยังไม่พบกลุ่ม LINE นี้ในระบบ กรุณาเชิญบอทเข้ากลุ่ม แล้วพิมพ์ 1 ข้อความในกลุ่มเพื่อให้ระบบจับกลุ่มได้",
        });
      }
    } else {
      const telegramBot = await db
        .collection("telegram_notification_bots")
        .findOne(
          { _id: new ObjectId(telegramBotId) },
          { projection: { _id: 1, isActive: 1 } },
        );
      if (!telegramBot) {
        return res.status(400).json({
          success: false,
          error: "ไม่พบ Telegram Bot ที่ระบุ",
        });
      }

      const chat = await db.collection("telegram_bot_groups").findOne({
        botId: telegramBotId,
        chatId: telegramChatId,
        status: { $ne: "left" },
      });
      if (!chat) {
        return res.status(400).json({
          success: false,
          error:
            "ยังไม่พบกลุ่ม Telegram นี้ในระบบ กรุณาเพิ่มบอทเข้ากลุ่ม แล้วส่งข้อความในกลุ่มเพื่อให้ระบบจับกลุ่มได้",
        });
      }
    }

    const now = new Date();
    const doc = {
      name,
      type: channelType,
      senderBotId: channelType === "line_group" ? senderBotId : null,
      groupId: channelType === "line_group" ? groupId : null,
      telegramBotId: channelType === "telegram_group" ? telegramBotId : null,
      telegramChatId: channelType === "telegram_group" ? telegramChatId : null,
      receiveFromAllBots: receiveAll,
      sources: receiveAll ? [] : sources,
      eventTypes: ["new_order"],
      deliveryMode,
      summaryTimes,
      summaryTimezone: BANGKOK_TZ,
      settings,
      isActive: isActive !== false,
      createdAt: now,
      updatedAt: now,
    };

    const result = await db.collection("notification_channels").insertOne(doc);
    doc._id = result.insertedId;
    await maybeMirrorAppDocumentFromCollection("notification_channels", doc);

    res.status(201).json({ success: true, channel: mapNotificationChannelDoc(doc) });
  } catch (err) {
    console.error("[Notifications] Error creating channel:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

app.put("/admin/api/notification-channels/:id", requireAdmin, async (req, res) => {
  try {
    const channelId = req.params.id;
    if (!ObjectId.isValid(channelId)) {
      return res.status(400).json({ success: false, error: "Channel ID ไม่ถูกต้อง" });
    }

    const name = typeof req.body?.name === "string" ? req.body.name.trim() : "";
    const channelType = normalizeNotificationChannelType(req.body?.type);
    const senderBotId =
      typeof req.body?.senderBotId === "string"
        ? req.body.senderBotId.trim()
        : "";
    const groupId =
      typeof req.body?.groupId === "string" ? req.body.groupId.trim() : "";
    const telegramBotId =
      typeof req.body?.telegramBotId === "string"
        ? req.body.telegramBotId.trim()
        : "";
    const telegramChatId =
      typeof req.body?.telegramChatId === "string"
        ? req.body.telegramChatId.trim()
        : "";

    if (!name) {
      return res.status(400).json({
        success: false,
        error: "กรุณากรอกชื่อช่องทางแจ้งเตือน",
      });
    }

    if (channelType === "line_group" && (!ObjectId.isValid(senderBotId) || !groupId)) {
      return res.status(400).json({
        success: false,
        error: "กรุณากรอก senderBotId และ groupId ให้ถูกต้องสำหรับ LINE",
      });
    }

    if (
      channelType === "telegram_group" &&
      (!ObjectId.isValid(telegramBotId) || !telegramChatId)
    ) {
      return res.status(400).json({
        success: false,
        error: "กรุณากรอก telegramBotId และ telegramChatId ให้ถูกต้อง",
      });
    }

    const receiveFromAllBots = parseOptionalBoolean(req.body?.receiveFromAllBots);
    const sources = normalizeNotificationSourcesInput(req.body?.sources || []);
    const settings = normalizeNotificationChannelSettings(req.body?.settings || {}, {
      channelType,
    });
    const isActive = parseOptionalBoolean(req.body?.isActive);
    const receiveAll = receiveFromAllBots !== false;
    const deliveryMode = normalizeNotificationDeliveryMode(
      req.body?.deliveryMode,
    );
    const summaryTimes = normalizeNotificationSummaryTimes(
      req.body?.summaryTimes,
    );

    if (!receiveAll && sources.length === 0) {
      return res.status(400).json({
        success: false,
        error: "กรุณาเลือกบอทต้นทางอย่างน้อย 1 รายการ หรือเลือก 'รับจากทุกบอท'",
      });
    }

    if (deliveryMode === "scheduled" && summaryTimes.length === 0) {
      return res.status(400).json({
        success: false,
        error: "กรุณาระบุเวลาสรุปอย่างน้อย 1 เวลา",
      });
    }

    const client = await connectDB();
    const db = client.db("chatbot");

    const existing = await db
      .collection("notification_channels")
      .findOne({ _id: new ObjectId(channelId) });
    if (!existing) {
      return res.status(404).json({ success: false, error: "ไม่พบช่องทางที่ระบุ" });
    }

    if (channelType === "line_group") {
      const senderBot = await db
        .collection("line_bots")
        .findOne({ _id: new ObjectId(senderBotId) }, { projection: { _id: 1 } });
      if (!senderBot) {
        return res.status(400).json({ success: false, error: "ไม่พบ LINE Bot ที่ระบุ" });
      }

      const group = await db.collection("line_bot_groups").findOne({
        botId: senderBotId,
        groupId,
        status: { $ne: "left" },
      });
      if (!group) {
        return res.status(400).json({
          success: false,
          error:
            "ยังไม่พบกลุ่ม LINE นี้ในระบบ กรุณาเชิญบอทเข้ากลุ่ม แล้วพิมพ์ 1 ข้อความในกลุ่มเพื่อให้ระบบจับกลุ่มได้",
        });
      }
    } else {
      const telegramBot = await db
        .collection("telegram_notification_bots")
        .findOne(
          { _id: new ObjectId(telegramBotId) },
          { projection: { _id: 1, isActive: 1 } },
        );
      if (!telegramBot) {
        return res.status(400).json({
          success: false,
          error: "ไม่พบ Telegram Bot ที่ระบุ",
        });
      }

      const chat = await db.collection("telegram_bot_groups").findOne({
        botId: telegramBotId,
        chatId: telegramChatId,
        status: { $ne: "left" },
      });
      if (!chat) {
        return res.status(400).json({
          success: false,
          error:
            "ยังไม่พบกลุ่ม Telegram นี้ในระบบ กรุณาเพิ่มบอทเข้ากลุ่ม แล้วส่งข้อความในกลุ่มเพื่อให้ระบบจับกลุ่มได้",
        });
      }
    }

    const update = {
      name,
      type: channelType,
      senderBotId: channelType === "line_group" ? senderBotId : null,
      groupId: channelType === "line_group" ? groupId : null,
      telegramBotId: channelType === "telegram_group" ? telegramBotId : null,
      telegramChatId: channelType === "telegram_group" ? telegramChatId : null,
      receiveFromAllBots: receiveAll,
      sources: receiveAll ? [] : sources,
      eventTypes: ["new_order"],
      deliveryMode,
      summaryTimes,
      summaryTimezone: BANGKOK_TZ,
      settings,
      updatedAt: new Date(),
    };
    if (typeof isActive === "boolean") {
      update.isActive = isActive;
    }

    await db
      .collection("notification_channels")
      .updateOne({ _id: new ObjectId(channelId) }, { $set: update });

    const updated = await db
      .collection("notification_channels")
      .findOne({ _id: new ObjectId(channelId) });
    await maybeMirrorAppDocumentFromCollection("notification_channels", updated);

    res.json({ success: true, channel: mapNotificationChannelDoc(updated) });
  } catch (err) {
    console.error("[Notifications] Error updating channel:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

app.patch(
  "/admin/api/notification-channels/:id/toggle",
  requireAdmin,
  async (req, res) => {
    try {
      const channelId = req.params.id;
      if (!ObjectId.isValid(channelId)) {
        return res.status(400).json({ success: false, error: "Channel ID ไม่ถูกต้อง" });
      }

      const client = await connectDB();
      const db = client.db("chatbot");
      const coll = db.collection("notification_channels");

      const existing = await coll.findOne({ _id: new ObjectId(channelId) });
      if (!existing) {
        return res.status(404).json({ success: false, error: "ไม่พบช่องทางที่ระบุ" });
      }

      const requested = parseOptionalBoolean(req.body?.isActive);
      const nextValue = typeof requested === "boolean" ? requested : !existing.isActive;

      await coll.updateOne(
        { _id: new ObjectId(channelId) },
        { $set: { isActive: nextValue, updatedAt: new Date() } },
      );
      await maybeMirrorAppDocumentByQuery(db, "notification_channels", {
        _id: new ObjectId(channelId),
      });

      res.json({ success: true, isActive: nextValue });
    } catch (err) {
      console.error("[Notifications] Error toggling channel:", err);
      res.status(500).json({ success: false, error: err.message });
    }
  },
);

