app.get("/admin/api/notification-logs", requireAdmin, async (req, res) => {
  try {
    const channelId =
      typeof req.query.channelId === "string" ? req.query.channelId.trim() : "";
    const status = typeof req.query.status === "string" ? req.query.status.trim() : "";
    const limit = Math.min(parseInt(req.query.limit, 10) || 50, 200);

    const query = {};
    if (channelId) query.channelId = channelId;
    if (status) query.status = status;

    const from = typeof req.query.from === "string" ? req.query.from.trim() : "";
    const to = typeof req.query.to === "string" ? req.query.to.trim() : "";
    if (from || to) {
      query.createdAt = {};
      if (from) {
        const fromMoment = parseBangkokDateInput(from);
        if (fromMoment?.isValid()) {
          query.createdAt.$gte = fromMoment.startOf("day").toDate();
        }
      }
      if (to) {
        const toMoment = parseBangkokDateInput(to);
        if (toMoment?.isValid()) {
          query.createdAt.$lte = toMoment.endOf("day").toDate();
        }
      }
      if (!Object.keys(query.createdAt).length) {
        delete query.createdAt;
      }
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const logs = await db
      .collection("notification_logs")
      .find(query)
      .sort({ createdAt: -1 })
      .limit(limit)
      .toArray();

    res.json({
      success: true,
      logs: logs.map((log) => ({
        id: log._id?.toString?.() || "",
        channelId: log.channelId || null,
        orderId: log.orderId || null,
        eventType: log.eventType || null,
        status: log.status || null,
        errorMessage: log.errorMessage || null,
        createdAt: log.createdAt || null,
      })),
    });
  } catch (err) {
    console.error("[Notifications] Error listing logs:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

