// GET: Usage statistics summary
function parseApiUsageDateRange(startDateStr, endDateStr) {
  const now = getBangkokMoment();
  let startMoment = startDateStr ? parseBangkokDateInput(startDateStr) : null;
  let endMoment = endDateStr ? parseBangkokDateInput(endDateStr) : null;

  if (!startMoment || !startMoment.isValid()) {
    startMoment = null;
  }
  if (!endMoment || !endMoment.isValid()) {
    endMoment = null;
  }

  if (!startMoment && endMoment) {
    startMoment = endMoment.clone();
  } else if (!endMoment && startMoment) {
    endMoment = startMoment.clone();
  }

  if (!startMoment && !endMoment) {
    startMoment = now.clone().subtract(6, "days");
    endMoment = now.clone();
  }

  startMoment = startMoment.startOf("day");
  endMoment = endMoment.endOf("day");
  if (endMoment.isBefore(startMoment)) {
    endMoment = startMoment.clone().endOf("day");
  }

  return { startMoment, endMoment };
}

const OPENAI_USAGE_COLLECTION = "openai_usage_logs";
const OPENAI_USAGE_TIMESTAMP_SQL = "(payload->>'timestamp')::timestamptz";
const OPENAI_USAGE_PROMPT_TOKENS_SQL =
  "CASE WHEN payload->>'promptTokens' ~ '^-?[0-9]+(\\\\.[0-9]+)?$' THEN (payload->>'promptTokens')::numeric ELSE 0 END";
const OPENAI_USAGE_COMPLETION_TOKENS_SQL =
  "CASE WHEN payload->>'completionTokens' ~ '^-?[0-9]+(\\\\.[0-9]+)?$' THEN (payload->>'completionTokens')::numeric ELSE 0 END";
const OPENAI_USAGE_TOTAL_TOKENS_SQL =
  "CASE WHEN payload->>'totalTokens' ~ '^-?[0-9]+(\\\\.[0-9]+)?$' THEN (payload->>'totalTokens')::numeric ELSE 0 END";
const OPENAI_USAGE_COST_SQL =
  "CASE WHEN payload->>'estimatedCost' ~ '^-?[0-9]+(\\\\.[0-9]+)?$' THEN (payload->>'estimatedCost')::numeric ELSE 0 END";

function buildOpenAiUsagePostgresFilter({
  startMoment,
  endMoment,
  keyId,
  botId,
  platform,
  provider,
}) {
  const params = [
    OPENAI_USAGE_COLLECTION,
    startMoment.toDate().toISOString(),
    endMoment.toDate().toISOString(),
  ];
  const clauses = [
    "collection_name = $1",
    `${OPENAI_USAGE_TIMESTAMP_SQL} >= $2::timestamptz`,
    `${OPENAI_USAGE_TIMESTAMP_SQL} <= $3::timestamptz`,
  ];

  const addPayloadEquals = (field, value) => {
    params.push(String(value));
    clauses.push(`payload->>'${field}' = $${params.length}`);
  };

  if (keyId && ObjectId.isValid(keyId)) addPayloadEquals("apiKeyId", keyId);
  if (botId) addPayloadEquals("botId", botId);
  if (platform) addPayloadEquals("platform", platform);
  if (provider) addPayloadEquals("provider", normalizeProvider(provider));

  return {
    params,
    whereSql: clauses.join(" AND "),
  };
}

async function queryOpenAiUsageSummaryFromPostgres(filters) {
  if (isPostgresNativeReadEnabled()) {
    const nativeSummary =
      await postgresNativeReadRepository.queryOpenAiUsageSummary(filters);
    if (nativeSummary) {
      return nativeSummary;
    }
  }

  const { params, whereSql } = buildOpenAiUsagePostgresFilter(filters);
  const withFiltered = `
    WITH filtered AS (
      SELECT payload
      FROM app_documents
      WHERE ${whereSql}
    )
  `;

  const totalsResult = await postgresRuntime.query(
    `
      ${withFiltered}
      SELECT
        COUNT(*)::integer AS "totalCalls",
        COALESCE(SUM(${OPENAI_USAGE_PROMPT_TOKENS_SQL}), 0)::float8 AS "totalPromptTokens",
        COALESCE(SUM(${OPENAI_USAGE_COMPLETION_TOKENS_SQL}), 0)::float8 AS "totalCompletionTokens",
        COALESCE(SUM(${OPENAI_USAGE_TOTAL_TOKENS_SQL}), 0)::float8 AS "totalTokens",
        COALESCE(SUM(${OPENAI_USAGE_COST_SQL}), 0)::float8 AS "totalCost",
        COUNT(*) FILTER (WHERE payload->>'estimatedCost' IS NOT NULL)::integer AS "pricedCalls",
        COUNT(*) FILTER (WHERE payload->>'estimatedCost' IS NULL)::integer AS "unpricedCalls"
      FROM filtered
    `,
    params,
  );

  const byModelResult = await postgresRuntime.query(
    `
      ${withFiltered}
      SELECT
        jsonb_build_object(
          'model', COALESCE(NULLIF(payload->>'model', ''), 'unknown'),
          'provider', COALESCE(NULLIF(payload->>'provider', ''), $${params.length + 1})
        ) AS _id,
        COUNT(*)::integer AS calls,
        COALESCE(SUM(${OPENAI_USAGE_TOTAL_TOKENS_SQL}), 0)::float8 AS tokens,
        COALESCE(SUM(${OPENAI_USAGE_COST_SQL}), 0)::float8 AS cost,
        COUNT(*) FILTER (WHERE payload->>'estimatedCost' IS NOT NULL)::integer AS "pricedCalls"
      FROM filtered
      GROUP BY COALESCE(NULLIF(payload->>'model', ''), 'unknown'),
        COALESCE(NULLIF(payload->>'provider', ''), $${params.length + 1})
      ORDER BY cost DESC
      LIMIT 10
    `,
    [...params, LLM_PROVIDER_OPENAI],
  );

  const byBotWhere = filters.botId
    ? ""
    : "WHERE payload->>'botId' IS NOT NULL AND payload->>'botId' <> ''";
  const byBotResult = await postgresRuntime.query(
    `
      ${withFiltered}
      SELECT
        jsonb_build_object(
          'botId', payload->>'botId',
          'platform', payload->>'platform'
        ) AS _id,
        COUNT(*)::integer AS calls,
        COALESCE(SUM(${OPENAI_USAGE_TOTAL_TOKENS_SQL}), 0)::float8 AS tokens,
        COALESCE(SUM(${OPENAI_USAGE_COST_SQL}), 0)::float8 AS cost,
        COUNT(*) FILTER (WHERE payload->>'estimatedCost' IS NOT NULL)::integer AS "pricedCalls"
      FROM filtered
      ${byBotWhere}
      GROUP BY payload->>'botId', payload->>'platform'
      ORDER BY cost DESC
      LIMIT 20
    `,
    params,
  );

  const byKeyWhere = filters.keyId
    ? ""
    : "WHERE payload->>'apiKeyId' IS NOT NULL AND payload->>'apiKeyId' <> ''";
  const byKeyResult = await postgresRuntime.query(
    `
      ${withFiltered}
      SELECT
        payload->>'apiKeyId' AS _id,
        COUNT(*)::integer AS calls,
        COALESCE(SUM(${OPENAI_USAGE_TOTAL_TOKENS_SQL}), 0)::float8 AS tokens,
        COALESCE(SUM(${OPENAI_USAGE_COST_SQL}), 0)::float8 AS cost,
        COUNT(*) FILTER (WHERE payload->>'estimatedCost' IS NOT NULL)::integer AS "pricedCalls"
      FROM filtered
      ${byKeyWhere}
      GROUP BY payload->>'apiKeyId'
      ORDER BY cost DESC
    `,
    params,
  );

  const dailyResult = await postgresRuntime.query(
    `
      ${withFiltered}
      SELECT
        to_char(${OPENAI_USAGE_TIMESTAMP_SQL} AT TIME ZONE $${params.length + 1}, 'YYYY-MM-DD') AS _id,
        COUNT(*)::integer AS calls,
        COALESCE(SUM(${OPENAI_USAGE_TOTAL_TOKENS_SQL}), 0)::float8 AS tokens,
        COALESCE(SUM(${OPENAI_USAGE_COST_SQL}), 0)::float8 AS cost,
        COUNT(*) FILTER (WHERE payload->>'estimatedCost' IS NOT NULL)::integer AS "pricedCalls"
      FROM filtered
      GROUP BY _id
      ORDER BY _id ASC
    `,
    [...params, BANGKOK_TZ],
  );

  return {
    totals: totalsResult.rows,
    byModel: byModelResult.rows,
    byBot: byBotResult.rows,
    byKey: byKeyResult.rows,
    daily: dailyResult.rows,
  };
}

app.get("/api/openai-usage/summary", async (req, res) => {
  try {
    const cacheHash = buildAdminCacheHash(req.query || {});
    const cachedResponse = await getCachedAdminJson(
      req,
      ["openai-usage-summary", cacheHash],
      async () => {
    const { startDate, endDate, keyId, botId, platform, provider } = req.query;

    const { startMoment, endMoment } = parseApiUsageDateRange(
      startDate,
      endDate,
    );
    const match = {
      timestamp: { $gte: startMoment.toDate(), $lte: endMoment.toDate() },
    };

    if (keyId && ObjectId.isValid(keyId)) {
      match.apiKeyId = new ObjectId(keyId);
    }
    if (botId) match.botId = botId;
    if (platform) match.platform = platform;
    if (provider) match.provider = normalizeProvider(provider);

    let totals;
    let byModel;
    let byBot;
    let byKey;
    let daily;

    if (shouldUsePostgresDocumentCompatDb()) {
      const postgresSummary = await queryOpenAiUsageSummaryFromPostgres({
        startMoment,
        endMoment,
        keyId,
        botId,
        platform,
        provider,
      });
      totals = postgresSummary.totals;
      byModel = postgresSummary.byModel;
      byBot = postgresSummary.byBot;
      byKey = postgresSummary.byKey;
      daily = postgresSummary.daily;
    } else {
      [totals, byModel, byBot, byKey, daily] = await Promise.all([
      // Overall totals
      db.collection("openai_usage_logs").aggregate([
        { $match: match },
        {
          $group: {
            _id: null,
            totalCalls: { $sum: 1 },
            totalPromptTokens: { $sum: "$promptTokens" },
            totalCompletionTokens: { $sum: "$completionTokens" },
            totalTokens: { $sum: "$totalTokens" },
            totalCost: { $sum: { $ifNull: ["$estimatedCost", 0] } },
            pricedCalls: {
              $sum: {
                $cond: [{ $ne: ["$estimatedCost", null] }, 1, 0],
              },
            },
            unpricedCalls: {
              $sum: {
                $cond: [{ $eq: ["$estimatedCost", null] }, 1, 0],
              },
            },
          }
        }
      ]).toArray(),

      // By model
      db.collection("openai_usage_logs").aggregate([
        { $match: match },
        {
          $group: {
            _id: { model: "$model", provider: "$provider" },
            calls: { $sum: 1 },
            tokens: { $sum: "$totalTokens" },
            cost: { $sum: { $ifNull: ["$estimatedCost", 0] } },
            pricedCalls: {
              $sum: {
                $cond: [{ $ne: ["$estimatedCost", null] }, 1, 0],
              },
            },
          }
        },
        { $sort: { cost: -1 } },
        { $limit: 10 }
      ]).toArray(),

      // By bot
      db.collection("openai_usage_logs").aggregate([
        {
          $match: {
            ...match,
            ...(match.botId ? {} : { botId: { $ne: null } }),
          },
        },
        {
          $group: {
            _id: { botId: "$botId", platform: "$platform" },
            calls: { $sum: 1 },
            tokens: { $sum: "$totalTokens" },
            cost: { $sum: { $ifNull: ["$estimatedCost", 0] } },
            pricedCalls: {
              $sum: {
                $cond: [{ $ne: ["$estimatedCost", null] }, 1, 0],
              },
            },
          }
        },
        { $sort: { cost: -1 } },
        { $limit: 20 }
      ]).toArray(),

      // By key
      db.collection("openai_usage_logs").aggregate([
        {
          $match: {
            ...match,
            ...(match.apiKeyId ? {} : { apiKeyId: { $ne: null } }),
          },
        },
        {
          $group: {
            _id: "$apiKeyId",
            calls: { $sum: 1 },
            tokens: { $sum: "$totalTokens" },
            cost: { $sum: { $ifNull: ["$estimatedCost", 0] } },
            pricedCalls: {
              $sum: {
                $cond: [{ $ne: ["$estimatedCost", null] }, 1, 0],
              },
            },
          }
        },
        { $sort: { cost: -1 } }
      ]).toArray(),

      // Daily usage (last 30 days)
      db.collection("openai_usage_logs").aggregate([
        { $match: match },
        {
          $group: {
            _id: {
              $dateToString: {
                format: "%Y-%m-%d",
                date: "$timestamp",
                timezone: BANGKOK_TZ,
              },
            },
            calls: { $sum: 1 },
            tokens: { $sum: "$totalTokens" },
            cost: { $sum: { $ifNull: ["$estimatedCost", 0] } },
            pricedCalls: {
              $sum: {
                $cond: [{ $ne: ["$estimatedCost", null] }, 1, 0],
              },
            },
          }
        },
        { $sort: { _id: 1 } }
      ]).toArray(),
      ]);
    }

    const client = await connectDB();
    const db = client.db("chatbot");

    // Enrich bot data with names
    const botIds = byBot.map(b => b._id.botId).filter(Boolean);
    const validBotIds = botIds.filter(id => ObjectId.isValid(id));
    const [lineBots, facebookBots, instagramBots, whatsappBots] =
      await Promise.all([
      validBotIds.length > 0
        ? db.collection("line_bots").find({ _id: { $in: validBotIds.map(id => new ObjectId(id)) } }).toArray()
        : [],
      validBotIds.length > 0
        ? db.collection("facebook_bots").find({ _id: { $in: validBotIds.map(id => new ObjectId(id)) } }).toArray()
        : [],
      validBotIds.length > 0
        ? db.collection("instagram_bots").find({ _id: { $in: validBotIds.map(id => new ObjectId(id)) } }).toArray()
        : [],
      validBotIds.length > 0
        ? db.collection("whatsapp_bots").find({ _id: { $in: validBotIds.map(id => new ObjectId(id)) } }).toArray()
        : [],
      ]);

    const botNameMap = {
      'instruction-chat': 'Instruction Chat (Admin)',
    };
    [...lineBots, ...facebookBots, ...instagramBots, ...whatsappBots].forEach(b => {
      botNameMap[b._id.toString()] = b.name || b.pageName || b._id.toString();
    });

    // Enrich key data with names
    const keyIds = byKey.map(k => k._id).filter(id => id && ObjectId.isValid(id));
    const keys = keyIds.length > 0
      ? await db.collection("openai_api_keys").find({ _id: { $in: keyIds } }).toArray()
      : [];

    const keyNameMap = {};
    const keyProviderMap = {};
    keys.forEach(k => {
      keyNameMap[k._id.toString()] = k.name;
      keyProviderMap[k._id.toString()] = normalizeProvider(k.provider);
    });

    const summary = totals[0] || {
      totalCalls: 0,
      totalPromptTokens: 0,
      totalCompletionTokens: 0,
      totalTokens: 0,
      totalCost: 0,
      pricedCalls: 0,
      unpricedCalls: 0,
    };

    return {
      success: true,
      summary: {
        totalCalls: summary.totalCalls,
        totalPromptTokens: summary.totalPromptTokens,
        totalCompletionTokens: summary.totalCompletionTokens,
        totalTokens: summary.totalTokens,
        totalCostUSD: summary.totalCost,
        totalCostTHB: summary.totalCost * 33, // Approximate USD to THB (33 THB/USD)
        pricedCalls: summary.pricedCalls || 0,
        unpricedCalls: summary.unpricedCalls || 0,
      },
      byModel: byModel.map(m => ({
        model: m._id?.model || "unknown",
        provider: normalizeProvider(m._id?.provider),
        calls: m.calls,
        tokens: m.tokens,
        costUSD: m.cost,
        pricedCalls: m.pricedCalls || 0,
      })),
      byBot: byBot.map(b => ({
        botId: b._id.botId,
        platform: b._id.platform,
        name: botNameMap[b._id.botId] || b._id.botId,
        calls: b.calls,
        tokens: b.tokens,
        costUSD: b.cost,
        pricedCalls: b.pricedCalls || 0,
      })),
      byKey: byKey.map(k => ({
        keyId: k._id?.toString(),
        name: keyNameMap[k._id?.toString()] || "Unknown Key",
        provider: keyProviderMap[k._id?.toString()] || LLM_PROVIDER_OPENAI,
        calls: k.calls,
        tokens: k.tokens,
        costUSD: k.cost,
        pricedCalls: k.pricedCalls || 0,
      })),
      daily: daily.map(d => ({
        ...d,
        pricedCalls: d.pricedCalls || 0,
      })),
    };
      },
      { ttlSeconds: runtimeConfig.redis.adminCacheTtlSeconds },
    );
    res.json(cachedResponse);
  } catch (err) {
    console.error("[OpenAI Usage] Error getting summary:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

// GET: Detailed usage logs
app.get("/api/openai-usage", async (req, res) => {
  try {
    const {
      startDate,
      endDate,
      keyId,
      botId,
      platform,
      provider,
      page = 1,
      limit = 50,
    } = req.query;

    const { startMoment, endMoment } = parseApiUsageDateRange(
      startDate,
      endDate,
    );
    const match = {
      timestamp: { $gte: startMoment.toDate(), $lte: endMoment.toDate() },
    };
    if (keyId && ObjectId.isValid(keyId)) {
      match.apiKeyId = new ObjectId(keyId);
    }
    if (botId) match.botId = botId;
    if (platform) match.platform = platform;
    if (provider) match.provider = normalizeProvider(provider);

    if (isPostgresNativeReadEnabled()) {
      const nativeResult = await postgresNativeReadRepository.queryOpenAiUsageLogs({
        startMoment,
        endMoment,
        keyId,
        botId,
        platform,
        provider,
        page,
        limit,
      });
      return res.json({
        success: true,
        logs: nativeResult.logs.map(l => ({
          id: l._id.toString(),
          apiKeyId: l.apiKeyId?.toString(),
          botId: l.botId,
          platform: l.platform,
          provider: normalizeProvider(l.provider),
          model: l.model,
          promptTokens: l.promptTokens,
          completionTokens: l.completionTokens,
          totalTokens: l.totalTokens,
          estimatedCostUSD: l.estimatedCost ?? null,
          functionName: l.functionName,
          timestamp: l.timestamp,
        })),
        pagination: nativeResult.pagination,
      });
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const safeLimit = Math.min(Math.max(parseInt(limit, 10) || 50, 1), 200);
    const currentPage = Math.max(parseInt(page, 10) || 1, 1);
    const skip = (currentPage - 1) * safeLimit;

    const [logs, total] = await Promise.all([
      db.collection("openai_usage_logs")
        .find(match)
        .sort({ timestamp: -1 })
        .skip(skip)
        .limit(safeLimit)
        .toArray(),
      db.collection("openai_usage_logs").countDocuments(match),
    ]);

    res.json({
      success: true,
      logs: logs.map(l => ({
        id: l._id.toString(),
        apiKeyId: l.apiKeyId?.toString(),
        botId: l.botId,
        platform: l.platform,
        provider: normalizeProvider(l.provider),
        model: l.model,
        promptTokens: l.promptTokens,
        completionTokens: l.completionTokens,
        totalTokens: l.totalTokens,
        estimatedCostUSD: l.estimatedCost ?? null,
        functionName: l.functionName,
        timestamp: l.timestamp,
      })),
      pagination: {
        page: currentPage,
        limit: safeLimit,
        total,
        pages: Math.ceil(total / safeLimit),
      },
    });
  } catch (err) {
    console.error("[OpenAI Usage] Error getting logs:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

// GET: Drill-down usage by specific Bot
app.get("/api/openai-usage/by-bot/:botId", async (req, res) => {
  try {
    const { botId } = req.params;
    const { startDate, endDate } = req.query;

    const client = await connectDB();
    const db = client.db("chatbot");

    const { startMoment, endMoment } = parseApiUsageDateRange(
      startDate,
      endDate,
    );
    const match = {
      botId,
      timestamp: { $gte: startMoment.toDate(), $lte: endMoment.toDate() },
    };

    // Get usage breakdown by model
    const byModel = await db.collection("openai_usage_logs").aggregate([
      { $match: match },
      {
        $group: {
          _id: { model: "$model", provider: "$provider" },
          count: { $sum: 1 },
          totalTokens: { $sum: "$totalTokens" },
          promptTokens: { $sum: "$promptTokens" },
          completionTokens: { $sum: "$completionTokens" },
          estimatedCost: { $sum: { $ifNull: ["$estimatedCost", 0] } },
          pricedCalls: {
            $sum: {
              $cond: [{ $ne: ["$estimatedCost", null] }, 1, 0],
            },
          },
        }
      },
      { $sort: { count: -1 } }
    ]).toArray();

    // Get usage breakdown by API key
    const byKey = await db.collection("openai_usage_logs").aggregate([
      { $match: match },
      {
        $group: {
          _id: "$apiKeyId",
          count: { $sum: 1 },
          totalTokens: { $sum: "$totalTokens" },
          estimatedCost: { $sum: { $ifNull: ["$estimatedCost", 0] } },
          pricedCalls: {
            $sum: {
              $cond: [{ $ne: ["$estimatedCost", null] }, 1, 0],
            },
          },
        }
      },
      { $sort: { count: -1 } }
    ]).toArray();

    // Get daily trend
    const byDay = await db.collection("openai_usage_logs").aggregate([
      { $match: match },
      {
        $group: {
          _id: {
            $dateToString: {
              format: "%Y-%m-%d",
              date: "$timestamp",
              timezone: BANGKOK_TZ,
            },
          },
          count: { $sum: 1 },
          totalTokens: { $sum: "$totalTokens" },
          estimatedCost: { $sum: { $ifNull: ["$estimatedCost", 0] } },
          pricedCalls: {
            $sum: {
              $cond: [{ $ne: ["$estimatedCost", null] }, 1, 0],
            },
          },
        }
      },
      { $sort: { _id: -1 } },
      { $limit: 30 }
    ]).toArray();

    // Get recent logs
    const recentLogs = await db.collection("openai_usage_logs")
      .find(match)
      .sort({ timestamp: -1 })
      .limit(20)
      .toArray();

    // Get totals
    const totals = await db.collection("openai_usage_logs").aggregate([
      { $match: match },
      {
        $group: {
          _id: null,
          totalCalls: { $sum: 1 },
          totalTokens: { $sum: "$totalTokens" },
          totalCost: { $sum: { $ifNull: ["$estimatedCost", 0] } },
          pricedCalls: {
            $sum: {
              $cond: [{ $ne: ["$estimatedCost", null] }, 1, 0],
            },
          },
        }
      }
    ]).toArray();

    // Get API key names
    const keyIds = byKey.map(k => k._id).filter(id => id);
    const keyDocs = keyIds.length > 0 ? await db.collection("openai_api_keys")
      .find({ _id: { $in: keyIds.map(id => new ObjectId(id)) } })
      .toArray() : [];
    const keyMap = Object.fromEntries(
      keyDocs.map(k => [
        k._id.toString(),
        { name: k.name, provider: normalizeProvider(k.provider) },
      ]),
    );

    res.json({
      success: true,
      botId,
      totals: totals[0] || { totalCalls: 0, totalTokens: 0, totalCost: 0, pricedCalls: 0 },
      byModel: byModel.map(m => ({
        ...m,
        model: m._id?.model || "unknown",
        provider: normalizeProvider(m._id?.provider),
      })),
      byKey: byKey.map(k => ({
        ...k,
        keyId: k._id?.toString(),
        keyName: keyMap[k._id?.toString()]?.name || "Env Variable",
        provider: keyMap[k._id?.toString()]?.provider || LLM_PROVIDER_OPENAI,
      })),
      byDay: byDay.map(d => ({ date: d._id, ...d })),
      recentLogs: recentLogs.map(l => ({
        id: l._id.toString(),
        model: l.model,
        provider: normalizeProvider(l.provider),
        totalTokens: l.totalTokens,
        estimatedCost: l.estimatedCost ?? null,
        timestamp: l.timestamp,
        functionName: l.functionName
      }))
    });
  } catch (err) {
    console.error("[OpenAI Usage] Error getting bot drill-down:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

